 1Ôćĺpackage connector
 2Ôćĺ
 3Ôćĺimport (
 4Ôćĺ	"fmt"
 5Ôćĺ	"io/fs"
 6Ôćĺ	"os"
 7Ôćĺ	"path/filepath"
 8Ôćĺ	"sort"
 9Ôćĺ	"strings"
10Ôćĺ)
11Ôćĺ
12Ôćĺ// LoadRegistry scans bundled definitions and project-local definitions,
13Ôćĺ// returning a merged list. Project-local definitions can override bundled
14Ôćĺ// Tier 2/3 connectors but NOT Tier 1 (email providers).
15Ôćĺ// projectDir is the path to .nurge/connectors/definitions/ (empty string to skip).
16Ôćĺfunc LoadRegistry(projectDir string) ([]ConnectorDef, error) {
17Ôćĺ	defs := make(map[string]ConnectorDef)
18Ôćĺ
19Ôćĺ	// 1. Load bundled definitions
20Ôćĺ	entries, err := fs.ReadDir(bundledDefinitions, "definitions")
21Ôćĺ	if err != nil {
22Ôćĺ		return nil, fmt.Errorf("reading bundled definitions: %w", err)
23Ôćĺ	}
24Ôćĺ	for _, entry := range entries {
25Ôćĺ		if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".yaml") {
26Ôćĺ			continue
27Ôćĺ		}
28Ôćĺ		data, err := bundledDefinitions.ReadFile("definitions/" + entry.Name())
29Ôćĺ		if err != nil {
30Ôćĺ			continue
31Ôćĺ		}
32Ôćĺ		yamlDef, err := ParseYAML(data)
33Ôćĺ		if err != nil {
34Ôćĺ			continue // skip invalid bundled defs
35Ôćĺ		}
36Ôćĺ		defs[yamlDef.ID] = ConnectorDef{
37Ôćĺ			ID:       yamlDef.ID,
38Ôćĺ			Name:     yamlDef.Name,
39Ôćĺ			Type:     yamlDef.Type,
40Ôćĺ			Tier:     yamlDef.Tier,
41Ôćĺ			Required: yamlDef.Required,
42Ôćĺ			Def:      yamlDef,
43Ôćĺ		}
44Ôćĺ	}
45Ôćĺ
46Ôćĺ	// 2. Load project-local definitions (override Tier 2/3 only)
47Ôćĺ	if projectDir != "" {
48Ôćĺ		localEntries, err := os.ReadDir(projectDir)
49Ôćĺ		if err == nil { // silently skip if dir doesn't exist
50Ôćĺ			for _, entry := range localEntries {
51Ôćĺ				if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".yaml") {
52Ôćĺ					continue
53Ôćĺ				}
54Ôćĺ				data, err := os.ReadFile(filepath.Join(projectDir, entry.Name()))
55Ôćĺ				if err != nil {
56Ôćĺ					continue
57Ôćĺ				}
58Ôćĺ				yamlDef, err := ParseYAML(data)
59Ôćĺ				if err != nil {
60Ôćĺ					continue
61Ôćĺ				}
62Ôćĺ				// Tier 1 connectors cannot be overridden
63Ôćĺ				if existing, ok := defs[yamlDef.ID]; ok && existing.Tier == 1 {
64Ôćĺ					fmt.Fprintf(os.Stderr, "warning: project-local definition for %q ignored (Tier 1 connectors cannot be overridden)\n", yamlDef.ID)
65Ôćĺ					continue
66Ôćĺ				}
67Ôćĺ				defs[yamlDef.ID] = ConnectorDef{
68Ôćĺ					ID:       yamlDef.ID,
69Ôćĺ					Name:     yamlDef.Name,
70Ôćĺ					Type:     yamlDef.Type,
71Ôćĺ					Tier:     yamlDef.Tier,
72Ôćĺ					Required: yamlDef.Required,
73Ôćĺ					Def:      yamlDef,
74Ôćĺ				}
75Ôćĺ			}
76Ôćĺ		}
77Ôćĺ	}
78Ôćĺ
79Ôćĺ	// Convert to sorted slice: email first (required), then crm, then enrichment
80Ôćĺ	typeOrder := map[string]int{"email": 0, "crm": 1, "enrichment": 2, "sequencing": 3, "webhook": 4}
81Ôćĺ	result := make([]ConnectorDef, 0, len(defs))
82Ôćĺ	for _, d := range defs {
83Ôćĺ		result = append(result, d)
84Ôćĺ	}
85Ôćĺ	sort.Slice(result, func(i, j int) bool {
86Ôćĺ		oi := typeOrder[result[i].Type]
87Ôćĺ		oj := typeOrder[result[j].Type]
88Ôćĺ		if oi != oj {
89Ôćĺ			return oi < oj
90Ôćĺ		}
91Ôćĺ		return result[i].Name < result[j].Name
92Ôćĺ	})
93Ôćĺ
94Ôćĺ	return result, nil
95Ôćĺ}
96Ôćĺ

  1Ôćĺpackage connector
  2Ôćĺ
  3Ôćĺimport (
  4Ôćĺ	"fmt"
  5Ôćĺ
  6Ôćĺ	"gopkg.in/yaml.v3"
  7Ôćĺ)
  8Ôćĺ
  9Ôćĺ// YAMLConnector is the parsed representation of a connector YAML file.
 10Ôćĺtype YAMLConnector struct {
 11Ôćĺ	SchemaVersion int          `yaml:"schema_version"`
 12Ôćĺ	ID            string       `yaml:"id"`
 13Ôćĺ	Name          string       `yaml:"name"`
 14Ôćĺ	Type          string       `yaml:"type"`
 15Ôćĺ	Tier          int          `yaml:"tier"`
 16Ôćĺ	Required      bool         `yaml:"required"`
 17Ôćĺ	Description   string       `yaml:"description"`
 18Ôćĺ	Icon          string       `yaml:"icon"`
 19Ôćĺ	Auth          AuthConfig   `yaml:"auth"`
 20Ôćĺ	Credentials   CredConfig   `yaml:"credentials"`
 21Ôćĺ	Verify        VerifyConfig `yaml:"verify"`
 22Ôćĺ	Proxy         ProxyConfig  `yaml:"proxy"`
 23Ôćĺ}
 24Ôćĺ
 25Ôćĺ// AuthConfig describes how to authenticate with the service.
 26Ôćĺtype AuthConfig struct {
 27Ôćĺ	Method       string            `yaml:"method"` // oauth2, api_key, basic, webhook
 28Ôćĺ	AuthorizeURL string            `yaml:"authorize_url"`
 29Ôćĺ	TokenURL     string            `yaml:"token_url"`
 30Ôćĺ	Scopes       []string          `yaml:"scopes"`
 31Ôćĺ	AuthStyle    string            `yaml:"auth_style"`   // in_params, in_header
 32Ôćĺ	ExtraParams  map[string]string `yaml:"extra_params"`
 33Ôćĺ	// api_key fields
 34Ôćĺ	Header     string `yaml:"header"`
 35Ôćĺ	QueryParam string `yaml:"query_param"`
 36Ôćĺ	EnvVar     string `yaml:"env_var"`
 37Ôćĺ	// basic auth fields
 38Ôćĺ	UsernameVar string `yaml:"username_var"`
 39Ôćĺ	PasswordVar string `yaml:"password_var"`
 40Ôćĺ	// webhook fields
 41Ôćĺ	URLVar string `yaml:"url_var"`
 42Ôćĺ}
 43Ôćĺ
 44Ôćĺ// CredConfig describes where credentials come from.
 45Ôćĺtype CredConfig struct {
 46Ôćĺ	Source          string `yaml:"source"` // env, bundled, google_json, file, prompt
 47Ôćĺ	ClientIDVar     string `yaml:"client_id_var"`
 48Ôćĺ	ClientSecretVar string `yaml:"client_secret_var"`
 49Ôćĺ}
 50Ôćĺ
 51Ôćĺ// VerifyConfig describes the connection verification call.
 52Ôćĺtype VerifyConfig struct {
 53Ôćĺ	URL           string            `yaml:"url"`
 54Ôćĺ	Method        string            `yaml:"method"`
 55Ôćĺ	Headers       map[string]string `yaml:"headers"`
 56Ôćĺ	AccountFields []string          `yaml:"account_fields"`
 57Ôćĺ	AccountLabel  string            `yaml:"account_label"`
 58Ôćĺ}
 59Ôćĺ
 60Ôćĺ// ProxyConfig describes how to call the service's API.
 61Ôćĺtype ProxyConfig struct {
 62Ôćĺ	BaseURL    string `yaml:"base_url"`
 63Ôćĺ	AuthHeader string `yaml:"auth_header"`
 64Ôćĺ}
 65Ôćĺ
 66Ôćĺ// ParseYAML parses and validates a connector YAML definition.
 67Ôćĺfunc ParseYAML(data []byte) (*YAMLConnector, error) {
 68Ôćĺ	var def YAMLConnector
 69Ôćĺ	if err := yaml.Unmarshal(data, &def); err != nil {
 70Ôćĺ		return nil, fmt.Errorf("parsing YAML: %w", err)
 71Ôćĺ	}
 72Ôćĺ	if err := validateDef(&def); err != nil {
 73Ôćĺ		return nil, err
 74Ôćĺ	}
 75Ôćĺ	// Defaults
 76Ôćĺ	if def.Tier == 0 {
 77Ôćĺ		def.Tier = 2
 78Ôćĺ	}
 79Ôćĺ	if def.Verify.Method == "" {
 80Ôćĺ		def.Verify.Method = "GET"
 81Ôćĺ	}
 82Ôćĺ	return &def, nil
 83Ôćĺ}
 84Ôćĺ
 85Ôćĺfunc validateDef(d *YAMLConnector) error {
 86Ôćĺ	if d.SchemaVersion != 1 {
 87Ôćĺ		return fmt.Errorf("connector definition has unsupported schema_version: %d (expected 1)", d.SchemaVersion)
 88Ôćĺ	}
 89Ôćĺ	if d.ID == "" {
 90Ôćĺ		return fmt.Errorf("connector definition missing required field: id")
 91Ôćĺ	}
 92Ôćĺ	if d.Name == "" {
 93Ôćĺ		return fmt.Errorf("connector %q missing required field: name", d.ID)
 94Ôćĺ	}
 95Ôćĺ	if d.Type == "" {
 96Ôćĺ		return fmt.Errorf("connector %q missing required field: type", d.ID)
 97Ôćĺ	}
 98Ôćĺ	if d.Auth.Method == "" {
 99Ôćĺ		return fmt.Errorf("connector %q missing required field: auth.method", d.ID)
100Ôćĺ	}
101Ôćĺ
102Ôćĺ	switch d.Auth.Method {
103Ôćĺ	case "oauth2":
104Ôćĺ		if d.Auth.AuthorizeURL == "" {
105Ôćĺ			return fmt.Errorf("connector %q (oauth2) missing auth.authorize_url", d.ID)
106Ôćĺ		}
107Ôćĺ		if d.Auth.TokenURL == "" {
108Ôćĺ			return fmt.Errorf("connector %q (oauth2) missing auth.token_url", d.ID)
109Ôćĺ		}
110Ôćĺ	case "api_key":
111Ôćĺ		if d.Auth.Header == "" && d.Auth.QueryParam == "" {
112Ôćĺ			return fmt.Errorf("connector %q (api_key) missing auth.header or auth.query_param", d.ID)
113Ôćĺ		}
114Ôćĺ	case "basic":
115Ôćĺ		// valid ÔÇö credentials resolved at connect time
116Ôćĺ	case "webhook":
117Ôćĺ		// valid ÔÇö URL resolved at connect time
118Ôćĺ	default:
119Ôćĺ		return fmt.Errorf("connector %q has unknown auth.method: %q", d.ID, d.Auth.Method)
120Ôćĺ	}
121Ôćĺ
122Ôćĺ	return nil
123Ôćĺ}
124Ôćĺ

  1Ôćĺpackage connector
  2Ôćĺ
  3Ôćĺimport (
  4Ôćĺ	"context"
  5Ôćĺ	"encoding/json"
  6Ôćĺ	"fmt"
  7Ôćĺ	"os"
  8Ôćĺ
  9Ôćĺ	"golang.org/x/oauth2"
 10Ôćĺ	"golang.org/x/oauth2/google"
 11Ôćĺ)
 12Ôćĺ
 13Ôćĺfunc (g *GenericConnector) connectOAuth2(ctx context.Context) (*Result, error) {
 14Ôćĺ	var oauthCfg *oauth2.Config
 15Ôćĺ	var authOpts []oauth2.AuthCodeOption
 16Ôćĺ
 17Ôćĺ	if g.def.Credentials.Source == "google_json" {
 18Ôćĺ		// Google-specific: use google.ConfigFromJSON
 19Ôćĺ		credsData, err := g.loadGoogleCredentials()
 20Ôćĺ		if err != nil {
 21Ôćĺ			return nil, err
 22Ôćĺ		}
 23Ôćĺ		cfg, err := google.ConfigFromJSON(credsData, g.def.Auth.Scopes...)
 24Ôćĺ		if err != nil {
 25Ôćĺ			return nil, fmt.Errorf("parsing Google credentials: %w", err)
 26Ôćĺ		}
 27Ôćĺ		oauthCfg = cfg
 28Ôćĺ	} else {
 29Ôćĺ		// Generic OAuth2: build config from YAML
 30Ôćĺ		clientID, clientSecret, err := g.resolveOAuthCredentials()
 31Ôćĺ		if err != nil {
 32Ôćĺ			return nil, err
 33Ôćĺ		}
 34Ôćĺ		cfg, opts, err := g.buildOAuthConfig(clientID, clientSecret)
 35Ôćĺ		if err != nil {
 36Ôćĺ			return nil, err
 37Ôćĺ		}
 38Ôćĺ		oauthCfg = cfg
 39Ôćĺ		authOpts = opts
 40Ôćĺ	}
 41Ôćĺ
 42Ôćĺ	// Add extra_params as auth options for google_json too
 43Ôćĺ	if g.def.Credentials.Source == "google_json" {
 44Ôćĺ		for k, v := range g.def.Auth.ExtraParams {
 45Ôćĺ			authOpts = append(authOpts, oauth2.SetAuthURLParam(k, v))
 46Ôćĺ		}
 47Ôćĺ	}
 48Ôćĺ
 49Ôćĺ	// Run shared OAuth flow
 50Ôćĺ	token, err := OAuthFlow(ctx, oauthCfg, authOpts...)
 51Ôćĺ	if err != nil {
 52Ôćĺ		return nil, err
 53Ôćĺ	}
 54Ôćĺ
 55Ôćĺ	// Save token
 56Ôćĺ	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
 57Ôćĺ	tokenPath := tokenDir + "/token.json"
 58Ôćĺ	if err := os.MkdirAll(tokenDir, 0700); err != nil {
 59Ôćĺ		return nil, fmt.Errorf("creating connector dir: %w", err)
 60Ôćĺ	}
 61Ôćĺ	if err := saveToken(tokenPath, token); err != nil {
 62Ôćĺ		return nil, fmt.Errorf("saving token: %w", err)
 63Ôćĺ	}
 64Ôćĺ
 65Ôćĺ	// Save granted scopes for later scope-sufficiency checks
 66Ôćĺ	if len(g.def.Auth.Scopes) > 0 {
 67Ôćĺ		_ = SaveGrantedScopes(tokenDir, g.def.Auth.Scopes)
 68Ôćĺ	}
 69Ôćĺ
 70Ôćĺ	// Verify connection + get account identifier
 71Ôćĺ	account, err := g.runVerify(ctx, oauthCfg, token)
 72Ôćĺ	if err != nil {
 73Ôćĺ		// Non-fatal: connected but can't verify
 74Ôćĺ		account = "connected (unverified)"
 75Ôćĺ	}
 76Ôćĺ
 77Ôćĺ	return &Result{
 78Ôćĺ		Account: account,
 79Ôćĺ		Token:   token,
 80Ôćĺ	}, nil
 81Ôćĺ}
 82Ôćĺ
 83Ôćĺfunc (g *GenericConnector) connectAPIKey(ctx context.Context) (*Result, error) {
 84Ôćĺ	key := os.Getenv(g.def.Auth.EnvVar)
 85Ôćĺ	if key == "" {
 86Ôćĺ		// Check if stdin is a TTY for prompt
 87Ôćĺ		if fi, err := os.Stdin.Stat(); err == nil && fi.Mode()&os.ModeCharDevice != 0 {
 88Ôćĺ			fmt.Printf("Enter your %s API key: ", g.def.Name)
 89Ôćĺ			fmt.Scanln(&key)
 90Ôćĺ		}
 91Ôćĺ		if key == "" {
 92Ôćĺ			return nil, fmt.Errorf("%s API key not found. Set %s environment variable", g.def.Name, g.def.Auth.EnvVar)
 93Ôćĺ		}
 94Ôćĺ	}
 95Ôćĺ
 96Ôćĺ	// Save API key
 97Ôćĺ	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
 98Ôćĺ	if err := os.MkdirAll(tokenDir, 0700); err != nil {
 99Ôćĺ		return nil, fmt.Errorf("creating connector dir: %w", err)
100Ôćĺ	}
101Ôćĺ	credsPath := tokenDir + "/credentials.json"
102Ôćĺ	credsData, _ := json.Marshal(map[string]string{"api_key": key})
103Ôćĺ	if err := os.WriteFile(credsPath, credsData, 0600); err != nil {
104Ôćĺ		return nil, fmt.Errorf("saving credentials: %w", err)
105Ôćĺ	}
106Ôćĺ
107Ôćĺ	// Verify
108Ôćĺ	account, err := g.runVerifyAPIKey(ctx, key)
109Ôćĺ	if err != nil {
110Ôćĺ		account = "connected (unverified)"
111Ôćĺ	}
112Ôćĺ
113Ôćĺ	return &Result{
114Ôćĺ		Account: account,
115Ôćĺ		Meta:    map[string]string{"api_key": key},
116Ôćĺ	}, nil
117Ôćĺ}
118Ôćĺ
119Ôćĺfunc (g *GenericConnector) connectBasic(ctx context.Context) (*Result, error) {
120Ôćĺ	username := os.Getenv(g.def.Auth.UsernameVar)
121Ôćĺ	password := os.Getenv(g.def.Auth.PasswordVar)
122Ôćĺ	if username == "" || password == "" {
123Ôćĺ		return nil, fmt.Errorf("%s credentials not found. Set %s and %s environment variables",
124Ôćĺ			g.def.Name, g.def.Auth.UsernameVar, g.def.Auth.PasswordVar)
125Ôćĺ	}
126Ôćĺ
127Ôćĺ	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
128Ôćĺ	if err := os.MkdirAll(tokenDir, 0700); err != nil {
129Ôćĺ		return nil, fmt.Errorf("creating connector dir: %w", err)
130Ôćĺ	}
131Ôćĺ	credsData, _ := json.Marshal(map[string]string{"username": username, "password": password})
132Ôćĺ	if err := os.WriteFile(tokenDir+"/credentials.json", credsData, 0600); err != nil {
133Ôćĺ		return nil, fmt.Errorf("saving credentials: %w", err)
134Ôćĺ	}
135Ôćĺ
136Ôćĺ	return &Result{Account: username}, nil
137Ôćĺ}
138Ôćĺ
139Ôćĺfunc (g *GenericConnector) connectWebhook(ctx context.Context) (*Result, error) {
140Ôćĺ	webhookURL := os.Getenv(g.def.Auth.URLVar)
141Ôćĺ	if webhookURL == "" {
142Ôćĺ		if fi, err := os.Stdin.Stat(); err == nil && fi.Mode()&os.ModeCharDevice != 0 {
143Ôćĺ			fmt.Printf("Enter your %s webhook URL: ", g.def.Name)
144Ôćĺ			fmt.Scanln(&webhookURL)
145Ôćĺ		}
146Ôćĺ		if webhookURL == "" {
147Ôćĺ			return nil, fmt.Errorf("%s webhook URL not found. Set %s environment variable",
148Ôćĺ				g.def.Name, g.def.Auth.URLVar)
149Ôćĺ		}
150Ôćĺ	}
151Ôćĺ
152Ôćĺ	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
153Ôćĺ	if err := os.MkdirAll(tokenDir, 0700); err != nil {
154Ôćĺ		return nil, fmt.Errorf("creating connector dir: %w", err)
155Ôćĺ	}
156Ôćĺ	credsData, _ := json.Marshal(map[string]string{"webhook_url": webhookURL})
157Ôćĺ	if err := os.WriteFile(tokenDir+"/credentials.json", credsData, 0600); err != nil {
158Ôćĺ		return nil, fmt.Errorf("saving credentials: %w", err)
159Ôćĺ	}
160Ôćĺ
161Ôćĺ	return &Result{Account: webhookURL}, nil
162Ôćĺ}
163Ôćĺ
164Ôćĺ// buildOAuthConfig creates a generic oauth2.Config from the YAML definition.
165Ôćĺfunc (g *GenericConnector) buildOAuthConfig(clientID, clientSecret string) (*oauth2.Config, []oauth2.AuthCodeOption, error) {
166Ôćĺ	cfg := &oauth2.Config{
167Ôćĺ		ClientID:     clientID,
168Ôćĺ		ClientSecret: clientSecret,
169Ôćĺ		Scopes:       g.def.Auth.Scopes,
170Ôćĺ		Endpoint: oauth2.Endpoint{
171Ôćĺ			AuthURL:  g.def.Auth.AuthorizeURL,
172Ôćĺ			TokenURL: g.def.Auth.TokenURL,
173Ôćĺ		},
174Ôćĺ	}
175Ôćĺ
176Ôćĺ	// Auth style
177Ôćĺ	switch g.def.Auth.AuthStyle {
178Ôćĺ	case "in_params":
179Ôćĺ		cfg.Endpoint.AuthStyle = oauth2.AuthStyleInParams
180Ôćĺ	case "in_header":
181Ôćĺ		cfg.Endpoint.AuthStyle = oauth2.AuthStyleInHeader
182Ôćĺ	}
183Ôćĺ
184Ôćĺ	// Extra params become AuthCodeOptions
185Ôćĺ	var opts []oauth2.AuthCodeOption
186Ôćĺ	for k, v := range g.def.Auth.ExtraParams {
187Ôćĺ		opts = append(opts, oauth2.SetAuthURLParam(k, v))
188Ôćĺ	}
189Ôćĺ
190Ôćĺ	return cfg, opts, nil
191Ôćĺ}
192Ôćĺ
193Ôćĺ// resolveOAuthCredentials reads client ID and secret from the configured source.
194Ôćĺfunc (g *GenericConnector) resolveOAuthCredentials() (string, string, error) {
195Ôćĺ	cred := g.def.Credentials
196Ôćĺ
197Ôćĺ	switch cred.Source {
198Ôćĺ	case "env":
199Ôćĺ		id := os.Getenv(cred.ClientIDVar)
200Ôćĺ		secret := os.Getenv(cred.ClientSecretVar)
201Ôćĺ		if id == "" || secret == "" {
202Ôćĺ			return "", "", fmt.Errorf("%s credentials not configured.\n  Set %s and %s environment variables",
203Ôćĺ				g.def.Name, cred.ClientIDVar, cred.ClientSecretVar)
204Ôćĺ		}
205Ôćĺ		return id, secret, nil
206Ôćĺ
207Ôćĺ	case "prompt":
208Ôćĺ		if fi, err := os.Stdin.Stat(); err != nil || fi.Mode()&os.ModeCharDevice == 0 {
209Ôćĺ			return "", "", fmt.Errorf("%s requires interactive input for credentials. Set environment variables or use a credentials file instead", g.def.Name)
210Ôćĺ		}
211Ôćĺ		var id, secret string
212Ôćĺ		fmt.Printf("Enter %s client ID: ", g.def.Name)
213Ôćĺ		fmt.Scanln(&id)
214Ôćĺ		fmt.Printf("Enter %s client secret: ", g.def.Name)
215Ôćĺ		fmt.Scanln(&secret)
216Ôćĺ		if id == "" || secret == "" {
217Ôćĺ			return "", "", fmt.Errorf("client ID and secret are required")
218Ôćĺ		}
219Ôćĺ		return id, secret, nil
220Ôćĺ
221Ôćĺ	default:
222Ôćĺ		return "", "", fmt.Errorf("unsupported credential source %q for connector %s", cred.Source, g.def.ID)
223Ôćĺ	}
224Ôćĺ}
225Ôćĺ
226Ôćĺ// loadGoogleCredentials loads credentials for google_json source (fallback chain).
227Ôćĺfunc (g *GenericConnector) loadGoogleCredentials() ([]byte, error) {
228Ôćĺ	// 1. Explicit path from --credentials flag
229Ôćĺ	if g.credentials != "" {
230Ôćĺ		data, err := os.ReadFile(g.credentials)
231Ôćĺ		if err != nil {
232Ôćĺ			return nil, fmt.Errorf("reading credentials from %s: %w", g.credentials, err)
233Ôćĺ		}
234Ôćĺ		return data, nil
235Ôćĺ	}
236Ôćĺ
237Ôćĺ	// 2. Local file in project
238Ôćĺ	localPath := fmt.Sprintf(".nurge/connectors/%s/credentials.json", g.def.ID)
239Ôćĺ	if data, err := os.ReadFile(localPath); err == nil {
240Ôćĺ		return data, nil
241Ôćĺ	}
242Ôćĺ
243Ôćĺ	// 3. Bundled credentials
244Ôćĺ	if len(BundledCredentials) > 0 {
245Ôćĺ		return BundledCredentials, nil
246Ôćĺ	}
247Ôćĺ
248Ôćĺ	return nil, fmt.Errorf("no %s credentials found -- provide a credentials.json file", g.def.Name)
249Ôćĺ}
