  2Ôćĺ
  3Ôćĺimport (
  4Ôćĺ	"context"
  5Ôćĺ	"encoding/json"
  6Ôćĺ	"fmt"
  7Ôćĺ	"io"
  8Ôćĺ	"net/http"
  9Ôćĺ	"os"
 10Ôćĺ	"strings"
 11Ôćĺ
 12Ôćĺ	"golang.org/x/oauth2"
 13Ôćĺ)
 14Ôćĺ
 15Ôćĺ// runVerify calls the verify endpoint using the oauth2 token source (handles refresh).
 16Ôćĺfunc (g *GenericConnector) runVerify(ctx context.Context, cfg *oauth2.Config, token *oauth2.Token) (string, error) {
 17Ôćĺ	if g.def.Verify.URL == "" {
 18Ôćĺ		return "connected", nil
 19Ôćĺ	}
 20Ôćĺ
 21Ôćĺ	// Refresh token first so URL substitution uses a valid access token
 22Ôćĺ	ts := cfg.TokenSource(ctx, token)
 23Ôćĺ	freshToken, err := ts.Token()
 24Ôćĺ	if err != nil {
 25Ôćĺ		fmt.Fprintf(os.Stderr, "  warning: token refresh failed for %s: %v\n  Run `nurge connect %s` if operations fail\n", g.def.ID, err, g.def.ID)
 26Ôćĺ		freshToken = token // fall back to original if refresh fails
 27Ôćĺ	}
 28Ôćĺ	if freshToken.AccessToken == "" {
 29Ôćĺ		return "", fmt.Errorf("no valid access token: refresh failed (%v) and original token has empty access token", err)
 30Ôćĺ	}
 31Ôćĺ	client := oauth2.NewClient(ctx, ts)
 32Ôćĺ	url := strings.ReplaceAll(g.def.Verify.URL, "{{access_token}}", freshToken.AccessToken)
 33Ôćĺ
 34Ôćĺ	method := g.def.Verify.Method
 35Ôćĺ	if method == "" {
 36Ôćĺ		method = "GET"
 37Ôćĺ	}
 38Ôćĺ
 39Ôćĺ	req, err := http.NewRequestWithContext(ctx, method, url, nil)
 40Ôćĺ	if err != nil {
 41Ôćĺ		return "", err
 42Ôćĺ	}
 43Ôćĺ	for k, v := range g.def.Verify.Headers {
 44Ôćĺ		v = strings.ReplaceAll(v, "{{access_token}}", freshToken.AccessToken)
 45Ôćĺ		req.Header.Set(k, v)
 46Ôćĺ	}
 47Ôćĺ
 48Ôćĺ	resp, err := client.Do(req)
 49Ôćĺ	if err != nil {
 50Ôćĺ		return "", err
 51Ôćĺ	}
 52Ôćĺ	defer resp.Body.Close()
 53Ôćĺ
 54Ôćĺ	if resp.StatusCode != 200 {
 55Ôćĺ		body, _ := io.ReadAll(resp.Body)
 56Ôćĺ		return "", ClassifyHTTPError(g.def.ID, resp.StatusCode, string(body))
 57Ôćĺ	}
 58Ôćĺ
 59Ôćĺ	return extractAccountField(resp.Body, g.def.Verify.AccountFields)
 60Ôćĺ}
 61Ôćĺ
 62Ôćĺ// runVerifyAPIKey calls verify with an API key in the configured header.
 63Ôćĺfunc (g *GenericConnector) runVerifyAPIKey(ctx context.Context, key string) (string, error) {
 64Ôćĺ	if g.def.Verify.URL == "" {
 65Ôćĺ		return "connected", nil
 66Ôćĺ	}
 67Ôćĺ
 68Ôćĺ	url := strings.ReplaceAll(g.def.Verify.URL, "{{api_key}}", key)
 69Ôćĺ	method := g.def.Verify.Method
 70Ôćĺ	if method == "" {
 71Ôćĺ		method = "GET"
 72Ôćĺ	}
 73Ôćĺ
 74Ôćĺ	req, err := http.NewRequestWithContext(ctx, method, url, nil)
 75Ôćĺ	if err != nil {
 76Ôćĺ		return "", err
 77Ôćĺ	}
 78Ôćĺ
 79Ôćĺ	if g.def.Auth.Header != "" {
 80Ôćĺ		req.Header.Set(g.def.Auth.Header, key)
 81Ôćĺ	}
 82Ôćĺ
 83Ôćĺ	resp, err := http.DefaultClient.Do(req)
 84Ôćĺ	if err != nil {
 85Ôćĺ		return "", err
 86Ôćĺ	}
 87Ôćĺ	defer resp.Body.Close()
 88Ôćĺ
 89Ôćĺ	if resp.StatusCode != 200 {
 90Ôćĺ		body, _ := io.ReadAll(resp.Body)
 91Ôćĺ		return "", ClassifyHTTPError(g.def.ID, resp.StatusCode, string(body))
 92Ôćĺ	}
 93Ôćĺ
 94Ôćĺ	return extractAccountField(resp.Body, g.def.Verify.AccountFields)
 95Ôćĺ}
 96Ôćĺ
 97Ôćĺ// extractAccountField reads the JSON response and tries fields in preference order.
 98Ôćĺfunc extractAccountField(body io.Reader, fields []string) (string, error) {
 99Ôćĺ	if len(fields) == 0 {
100Ôćĺ		return "connected", nil
101Ôćĺ	}
102Ôćĺ
103Ôćĺ	var data map[string]interface{}
104Ôćĺ	if err := json.NewDecoder(body).Decode(&data); err != nil {
105Ôćĺ		return "", fmt.Errorf("parsing verify response: %w", err)
106Ôćĺ	}
107Ôćĺ
108Ôćĺ	for _, field := range fields {
109Ôćĺ		if v, ok := data[field]; ok && v != nil {
110Ôćĺ			return fmt.Sprintf("%v", v), nil
111Ôćĺ		}
112Ôćĺ	}
113Ôćĺ
114Ôćĺ	return "connected", nil
115Ôćĺ}
