 10Ôćĺ// HealthStatus represents the outcome of a connector health check.
 11Ôćĺtype HealthStatus int
 12Ôćĺ
 13Ôćĺconst (
 14Ôćĺ	HealthOK           HealthStatus = iota
 15Ôćĺ	HealthTokenMissing              // config says connected but no auth files on disk
 16Ôćĺ	HealthTokenCorrupt              // auth file exists but contains invalid JSON
 17Ôćĺ	HealthOrphanedToken             // config says disconnected but auth files remain
 18Ôćĺ)
 19Ôćĺ
 20Ôćĺfunc (h HealthStatus) String() string {
 21Ôćĺ	switch h {
 22Ôćĺ	case HealthOK:
 23Ôćĺ		return "ok"
 24Ôćĺ	case HealthTokenMissing:
 25Ôćĺ		return "token_missing"
 26Ôćĺ	case HealthTokenCorrupt:
 27Ôćĺ		return "token_corrupt"
 28Ôćĺ	case HealthOrphanedToken:
 29Ôćĺ		return "orphaned_token"
 30Ôćĺ	default:
 31Ôćĺ		return "unknown"
 32Ôćĺ	}
 33Ôćĺ}
 34Ôćĺ
 35Ôćĺ// HealthResult holds the outcome of CheckHealth for a single connector.
 36Ôćĺtype HealthResult struct {
 37Ôćĺ	ConnectorID string
 38Ôćĺ	Status      HealthStatus
 39Ôćĺ	Message     string
 40Ôćĺ}
 41Ôćĺ
 42Ôćĺ// CheckHealth verifies consistency between a connector's config state
 43Ôćĺ// (connected or not) and its on-disk auth files (token.json / credentials.json).
 44Ôćĺ// When convexBacked is true, missing local auth files are expected (auth is server-managed).
 45Ôćĺfunc CheckHealth(connectorID, connectorDir string, configConnected bool, convexBacked bool) HealthResult {
 46Ôćĺ	tokenPath := filepath.Join(connectorDir, "token.json")
 47Ôćĺ	credsPath := filepath.Join(connectorDir, "credentials.json")
 48Ôćĺ
 49Ôćĺ	hasToken := fileExists(tokenPath)
 50Ôćĺ	hasCreds := fileExists(credsPath)
 51Ôćĺ	hasAnyAuth := hasToken || hasCreds
 52Ôćĺ
 53Ôćĺ	if configConnected {
 54Ôćĺ		if convexBacked {
 55Ôćĺ			// Convex-backed connectors don't need local auth files.
 56Ôćĺ			// Validate any files that do exist, but absence is normal.
 57Ôćĺ			if hasToken {
 58Ôćĺ				if err := validateJSON(tokenPath); err != nil {
 59Ôćĺ					return HealthResult{ConnectorID: connectorID, Status: HealthTokenCorrupt, Message: fmt.Sprintf("token.json is corrupt: %v", err)}
 60Ôćĺ				}
 61Ôćĺ			}
 62Ôćĺ			return HealthResult{ConnectorID: connectorID, Status: HealthOK, Message: "healthy (server-managed)"}
 63Ôćĺ		}
 64Ôćĺ		if !hasAnyAuth {
 65Ôćĺ			return HealthResult{
 66Ôćĺ				ConnectorID: connectorID,
 67Ôćĺ				Status:      HealthTokenMissing,
 68Ôćĺ				Message:     fmt.Sprintf("config says connected but no token/credentials found in %s", connectorDir),
 69Ôćĺ			}
 70Ôćĺ		}
 71Ôćĺ		if hasToken {
 72Ôćĺ			if err := validateJSON(tokenPath); err != nil {
 73Ôćĺ				return HealthResult{
 74Ôćĺ					ConnectorID: connectorID,
 75Ôćĺ					Status:      HealthTokenCorrupt,
 76Ôćĺ					Message:     fmt.Sprintf("token.json is corrupt: %v", err),
 77Ôćĺ				}
 78Ôćĺ			}
 79Ôćĺ		}
 80Ôćĺ		if hasCreds && !hasToken {
 81Ôćĺ			if err := validateJSON(credsPath); err != nil {
 82Ôćĺ				return HealthResult{
 83Ôćĺ					ConnectorID: connectorID,
 84Ôćĺ					Status:      HealthTokenCorrupt,
 85Ôćĺ					Message:     fmt.Sprintf("credentials.json is corrupt: %v", err),
 86Ôćĺ				}
 87Ôćĺ			}
 88Ôćĺ		}
 89Ôćĺ		return HealthResult{ConnectorID: connectorID, Status: HealthOK, Message: "healthy"}
 90Ôćĺ	}
 91Ôćĺ
 92Ôćĺ	// Not connected according to config.
 93Ôćĺ	if hasAnyAuth {
 94Ôćĺ		return HealthResult{
 95Ôćĺ			ConnectorID: connectorID,
 96Ôćĺ			Status:      HealthOrphanedToken,
 97Ôćĺ			Message:     fmt.Sprintf("config says disconnected but auth files exist in %s", connectorDir),
 98Ôćĺ		}
 99Ôćĺ	}
100Ôćĺ	return HealthResult{ConnectorID: connectorID, Status: HealthOK, Message: "clean"}
101Ôćĺ}
102Ôćĺ
103Ôćĺ// SaveGrantedScopes writes the granted OAuth scopes to scopes.json in the connector directory.
104Ôćĺfunc SaveGrantedScopes(connectorDir string, scopes []string) error {
105Ôćĺ	data, err := json.Marshal(scopes)
106Ôćĺ	if err != nil {
107Ôćĺ		return err
108Ôćĺ	}
109Ôćĺ	return os.WriteFile(filepath.Join(connectorDir, "scopes.json"), data, 0600)
110Ôćĺ}
111Ôćĺ
112Ôćĺ// LoadGrantedScopes reads the granted OAuth scopes from scopes.json.
113Ôćĺ// Returns nil, nil if the file does not exist (graceful for old tokens).
114Ôćĺfunc LoadGrantedScopes(connectorDir string) ([]string, error) {
115Ôćĺ	data, err := os.ReadFile(filepath.Join(connectorDir, "scopes.json"))
116Ôćĺ	if err != nil {
117Ôćĺ		if os.IsNotExist(err) {
118Ôćĺ			return nil, nil
119Ôćĺ		}
120Ôćĺ		return nil, err
121Ôćĺ	}
122Ôćĺ	var scopes []string
123Ôćĺ	return scopes, json.Unmarshal(data, &scopes)
124Ôćĺ}
125Ôćĺ
126Ôćĺ// CheckScopesSufficient returns true if all required scopes are present in granted.
127Ôćĺfunc CheckScopesSufficient(granted, required []string) bool {
128Ôćĺ	set := make(map[string]bool, len(granted))
129Ôćĺ	for _, s := range granted {
130Ôćĺ		set[s] = true
131Ôćĺ	}
132Ôćĺ	for _, s := range required {
133Ôćĺ		if !set[s] {
134Ôćĺ			return false
135Ôćĺ		}
136Ôćĺ	}
137Ôćĺ	return true
138Ôćĺ}
139Ôćĺ
140Ôćĺfunc fileExists(path string) bool {
141Ôćĺ	_, err := os.Stat(path)
142Ôćĺ	return err == nil
143Ôćĺ}
144Ôćĺ
145Ôćĺfunc validateJSON(path string) error {
146Ôćĺ	data, err := os.ReadFile(path)
147Ôćĺ	if err != nil {
148Ôćĺ		return err
149Ôćĺ	}
150Ôćĺ	var v interface{}
151Ôćĺ	return json.Unmarshal(data, &v)
152Ôćĺ}
