 1Ôćĺpackage connector
 2Ôćĺ
 3Ôćĺimport (
 4Ôćĺ	"errors"
 5Ôćĺ	"fmt"
 6Ôćĺ	"strings"
 7Ôćĺ)
 8Ôćĺ
 9Ôćĺ// AuthError wraps a connector authentication failure with actionable context.
10Ôćĺtype AuthError struct {
11Ôćĺ	ConnectorID string
12Ôćĺ	Reason      string
13Ôćĺ	Err         error
14Ôćĺ}
15Ôćĺ
16Ôćĺfunc (e *AuthError) Error() string { return fmt.Sprintf("connector %s: %s", e.ConnectorID, e.Reason) }
17Ôćĺfunc (e *AuthError) Unwrap() error { return e.Err }
18Ôćĺfunc (e *AuthError) Suggestion() string {
19Ôćĺ	return fmt.Sprintf("run `nurge connect %s` to reconnect", e.ConnectorID)
20Ôćĺ}
21Ôćĺ
22Ôćĺvar (
23Ôćĺ	ErrAuthExpired   = fmt.Errorf("authentication expired")
24Ôćĺ	ErrTokenRevoked  = fmt.Errorf("token revoked by provider")
25Ôćĺ	ErrScopeMismatch = fmt.Errorf("insufficient scopes")
26Ôćĺ)
27Ôćĺ
28Ôćĺ// IsAuthError reports whether err or any error in its chain is an *AuthError.
29Ôćĺfunc IsAuthError(err error) bool {
30Ôćĺ	var ae *AuthError
31Ôćĺ	return errors.As(err, &ae)
32Ôćĺ}
33Ôćĺ
34Ôćĺ// NewAuthExpiredError creates an AuthError for expired credentials.
35Ôćĺfunc NewAuthExpiredError(connectorID string, cause error) error {
36Ôćĺ	return &AuthError{
37Ôćĺ		ConnectorID: connectorID,
38Ôćĺ		Reason:      "authentication expired",
39Ôćĺ		Err:         fmt.Errorf("%w: %w", ErrAuthExpired, cause),
40Ôćĺ	}
41Ôćĺ}
42Ôćĺ
43Ôćĺ// NewTokenRevokedError creates an AuthError for revoked tokens.
44Ôćĺfunc NewTokenRevokedError(connectorID string, cause error) error {
45Ôćĺ	return &AuthError{
46Ôćĺ		ConnectorID: connectorID,
47Ôćĺ		Reason:      "token revoked by provider",
48Ôćĺ		Err:         fmt.Errorf("%w: %w", ErrTokenRevoked, cause),
49Ôćĺ	}
50Ôćĺ}
51Ôćĺ
52Ôćĺ// NewScopeMismatchError creates an AuthError for insufficient OAuth scopes.
53Ôćĺfunc NewScopeMismatchError(connectorID string, needed, granted []string) error {
54Ôćĺ	return &AuthError{
55Ôćĺ		ConnectorID: connectorID,
56Ôćĺ		Reason:      fmt.Sprintf("need scopes %v, have %v", needed, granted),
57Ôćĺ		Err:         ErrScopeMismatch,
58Ôćĺ	}
59Ôćĺ}
60Ôćĺ
61Ôćĺ// ClassifyHTTPError turns an HTTP status code and response body into a typed
62Ôćĺ// error. Auth-related codes (401, 403) produce an *AuthError; everything else
63Ôćĺ// returns a plain error.
64Ôćĺfunc ClassifyHTTPError(connectorID string, statusCode int, body string) error {
65Ôćĺ	switch {
66Ôćĺ	case statusCode == 401:
67Ôćĺ		return NewAuthExpiredError(connectorID, fmt.Errorf("HTTP %d", statusCode))
68Ôćĺ	case statusCode == 403:
69Ôćĺ		if strings.Contains(strings.ToLower(body), "revoked") {
70Ôćĺ			return NewTokenRevokedError(connectorID, fmt.Errorf("HTTP %d: %s", statusCode, body))
71Ôćĺ		}
72Ôćĺ		return NewAuthExpiredError(connectorID, fmt.Errorf("HTTP %d: %s", statusCode, body))
73Ôćĺ	default:
74Ôćĺ		return fmt.Errorf("HTTP %d: %s", statusCode, body)
75Ôćĺ	}
76Ôćĺ}
