 17Ôćĺvar forceConnect bool
 18Ôćĺ
 19Ôćĺfunc init() {
 20Ôćĺ	connectCmd.Flags().BoolVar(&forceConnect, "force", false, "Overwrite existing connection")
 21Ôćĺ}
 22Ôćĺ
 23Ôćĺfunc checkExistingConnection(id string) (bool, string) {
 24Ôćĺ	if !project.IsNurgeProject(".") {
 25Ôćĺ		return false, ""
 26Ôćĺ	}
 27Ôćĺ	cfg, err := project.Load()
 28Ôćĺ	if err != nil {
 29Ôćĺ		return false, ""
 30Ôćĺ	}
 31Ôćĺ	cs, ok := cfg.Connectors[id]
 32Ôćĺ	if !ok || !cs.Connected {
 33Ôćĺ		return false, ""
 34Ôćĺ	}
 35Ôćĺ	return true, cs.Account
 36Ôćĺ}
 37Ôćĺ
 38Ôćĺfunc acquireConnectLock(id string) (func(), error) {
 39Ôćĺ	lockDir := fmt.Sprintf(".nurge/connectors/%s", id)
 40Ôćĺ	if err := os.MkdirAll(lockDir, 0700); err != nil {
 41Ôćĺ		return nil, err
 42Ôćĺ	}
 43Ôćĺ	lockPath := filepath.Join(lockDir, ".connecting")
 44Ôćĺ	f, err := os.OpenFile(lockPath, os.O_CREATE|os.O_EXCL|os.O_WRONLY, 0600)
 45Ôćĺ	if err != nil {
 46Ôćĺ		if os.IsExist(err) {
 47Ôćĺ			return nil, fmt.Errorf("%s connection already in progress (remove %s if stale)", id, lockPath)
 48Ôćĺ		}
 49Ôćĺ		return nil, err
 50Ôćĺ	}
 51Ôćĺ	fmt.Fprintf(f, "%d", os.Getpid())
 52Ôćĺ	f.Close()
 53Ôćĺ	return func() { os.Remove(lockPath) }, nil
 54Ôćĺ}
 55Ôćĺ
 56Ôćĺvar connectCmd = &cobra.Command{
 57Ôćĺ	Use:   "connect <service>",
 58Ôćĺ	Short: "Connect a service (gmail, linkedin)",
 59Ôćĺ	Args:  cobra.ExactArgs(1),
 60Ôćĺ	RunE: func(cmd *cobra.Command, args []string) error {
 61Ôćĺ		id := args[0]
 62Ôćĺ		if connected, account := checkExistingConnection(id); connected {
 63Ôćĺ			if !forceConnect {
 64Ôćĺ				fmt.Fprintf(os.Stderr, "  %s is already connected (%s)\n  Use --force to reconnect\n", id, account)
 65Ôćĺ				return fmt.Errorf("%s already connected, use --force to overwrite", id)
 66Ôćĺ			}
 67Ôćĺ			// Clean up old connection state before reconnecting
 68Ôćĺ			fmt.Fprintf(os.Stderr, "  Replacing existing %s connection (%s)...\n", id, account)
 69Ôćĺ			tokenDir := fmt.Sprintf(".nurge/connectors/%s", id)
 70Ôćĺ			_ = os.RemoveAll(tokenDir)
 71Ôćĺ		}
 72Ôćĺ		cleanup, err := acquireConnectLock(id)
 73Ôćĺ		if err != nil {
 74Ôćĺ			return err
 75Ôćĺ		}
 76Ôćĺ		defer cleanup()
 77Ôćĺ		switch id {
 78Ôćĺ		case "gmail":
 79Ôćĺ			return connectGmail()
 80Ôćĺ		case "linkedin":
 81Ôćĺ			return connectLinkedIn()
 82Ôćĺ		default:
 83Ôćĺ			registry, err := connector.LoadRegistry(projectLocalDefs)
 84Ôćĺ			if err != nil {
 85Ôćĺ				return fmt.Errorf("loading connector registry: %w", err)
 86Ôćĺ			}
 87Ôćĺ			var found *connector.ConnectorDef
 88Ôćĺ			for i := range registry {
 89Ôćĺ				if registry[i].ID == id {
 90Ôćĺ					found = &registry[i]
 91Ôćĺ					break
 92Ôćĺ				}
 93Ôćĺ			}
 94Ôćĺ			if found == nil {
 95Ôćĺ				return fmt.Errorf("unknown connector: %s\n  Run `nurge connectors available` to see all connectors", id)
 96Ôćĺ			}
 97Ôćĺ			c := connector.NewFromDef(*found, "")
 98Ôćĺ			result, err := c.Connect(cmd.Context())
 99Ôćĺ			if err != nil {
100Ôćĺ				return fmt.Errorf("connecting %s: %w", id, err)
101Ôćĺ			}
102Ôćĺ			if project.IsNurgeProject(".") {
103Ôćĺ				_ = project.SetConnector(id, found.Type, result.Account)
104Ôćĺ			}
105Ôćĺ			fmt.Fprintf(os.Stderr, "  \033[32mÔťô\033[0m %s connected (%s)\n", found.Name, result.Account)
106Ôćĺ		}
107Ôćĺ		return nil
108Ôćĺ	},
109Ôćĺ}
110Ôćĺ
111Ôćĺfunc connectGmail() error {
112Ôćĺ	af, err := account.LoadAuth()
113Ôćĺ	if err != nil || af.Token == "" {
114Ôćĺ		return fmt.Errorf("not logged in. Run: nurge account login")
115Ôćĺ	}
116Ôćĺ
117Ôćĺ	client := account.NewConvexClient(cmdutil.GetConvexURL())
118Ôćĺ
119Ôćĺ	fmt.Fprintf(os.Stderr, "  Requesting Gmail connection...\n")
120Ôćĺ	resp, err := client.ConnectGmail(af.Token)
121Ôćĺ	if err != nil {
122Ôćĺ		return fmt.Errorf("connect failed: %w", err)
123Ôćĺ	}
124Ôćĺ
125Ôćĺ	if resp.AlreadyConnected {
126Ôćĺ		if resp.MaxReached {
127Ôćĺ			fmt.Fprintf(os.Stderr, "  \033[32mÔťô\033[0m Max 2 Gmail accounts connected (%s)\n", resp.Email)
