 55Ôćĺfunc Default() *Config {
 56Ôćĺ	return &Config{
 57Ôćĺ		Version:        1,
 58Ôćĺ		CreatedAt:      time.Now().UTC().Format(time.RFC3339),
 59Ôćĺ		Connectors:     make(map[string]ConnectorState),
