 64Ôćĺ// Load reads config from disk.
 65Ôćĺfunc Load() (*Config, error) {
 66Ôćĺ	data, err := os.ReadFile(configFile)
 67Ôćĺ	if err != nil {
 68Ôćĺ		return nil, fmt.Errorf("reading config: %w", err)
 69Ôćĺ	}
 70Ôćĺ	var cfg Config
 71Ôćĺ	if err := json.Unmarshal(data, &cfg); err != nil {
 72Ôćĺ		return nil, fmt.Errorf("parsing config: %w", err)
 73Ôćĺ	}
 74Ôćĺ	if cfg.Connectors == nil {
 75Ôćĺ		cfg.Connectors = make(map[string]ConnectorState)
 76Ôćĺ	}
 77Ôćĺ	return &cfg, nil
 78Ôćĺ}
