 80Ôćĺ// Write saves config to disk.
 81Ôćĺfunc Write(cfg *Config) error {
 82Ôćĺ	data, err := json.MarshalIndent(cfg, "", "  ")
 83Ôćĺ	if err != nil {
 84Ôćĺ		return fmt.Errorf("marshaling config: %w", err)
 85Ôćĺ	}
 86Ôćĺ	// Atomic write: write to temp file first, then rename.
 87Ôćĺ	// os.Rename is atomic on POSIX, preventing truncated files on crash.
 88Ôćĺ	tmpPath := configFile + ".tmp"
 89Ôćĺ	if err := os.WriteFile(tmpPath, data, 0600); err != nil {
 90Ôćĺ		return fmt.Errorf("writing config temp: %w", err)
 91Ôćĺ	}
 92Ôćĺ	if err := os.Rename(tmpPath, configFile); err != nil {
 93Ôćĺ		os.Remove(tmpPath)
 94Ôćĺ		return fmt.Errorf("renaming config: %w", err)
 95Ôćĺ	}
 96Ôćĺ	return nil
 97Ôćĺ}
