14Ôćĺ// Tier 2/3 connectors but NOT Tier 1 (email providers).
15Ôćĺ// projectDir is the path to .nurge/connectors/definitions/ (empty string to skip).
16Ôćĺfunc LoadRegistry(projectDir string) ([]ConnectorDef, error) {
17Ôćĺ	defs := make(map[string]ConnectorDef)
18Ôćĺ
19Ôćĺ	// 1. Load bundled definitions
20Ôćĺ	entries, err := fs.ReadDir(bundledDefinitions, "definitions")
21Ôćĺ	if err != nil {
22Ôćĺ		return nil, fmt.Errorf("reading bundled definitions: %w", err)
23Ôćĺ	}
24Ôćĺ	for _, entry := range entries {
25Ôćĺ		if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".yaml") {
26Ôćĺ			continue
27Ôćĺ		}
28Ôćĺ		data, err := bundledDefinitions.ReadFile("definitions/" + entry.Name())
29Ôćĺ		if err != nil {
30Ôćĺ			continue
31Ôćĺ		}
32Ôćĺ		yamlDef, err := ParseYAML(data)
33Ôćĺ		if err != nil {
34Ôćĺ			continue // skip invalid bundled defs
35Ôćĺ		}
36Ôćĺ		defs[yamlDef.ID] = ConnectorDef{
37Ôćĺ			ID:       yamlDef.ID,
38Ôćĺ			Name:     yamlDef.Name,
39Ôćĺ			Type:     yamlDef.Type,
40Ôćĺ			Tier:     yamlDef.Tier,
41Ôćĺ			Required: yamlDef.Required,
42Ôćĺ			Def:      yamlDef,
43Ôćĺ		}
44Ôćĺ	}
45Ôćĺ
46Ôćĺ	// 2. Load project-local definitions (override Tier 2/3 only)
47Ôćĺ	if projectDir != "" {
48Ôćĺ		localEntries, err := os.ReadDir(projectDir)
49Ôćĺ		if err == nil { // silently skip if dir doesn't exist
50Ôćĺ			for _, entry := range localEntries {
51Ôćĺ				if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".yaml") {
52Ôćĺ					continue
53Ôćĺ				}
54Ôćĺ				data, err := os.ReadFile(filepath.Join(projectDir, entry.Name()))
55Ôćĺ				if err != nil {
56Ôćĺ					continue
57Ôćĺ				}
58Ôćĺ				yamlDef, err := ParseYAML(data)
59Ôćĺ				if err != nil {
60Ôćĺ					continue
61Ôćĺ				}
62Ôćĺ				// Tier 1 connectors cannot be overridden
63Ôćĺ				if existing, ok := defs[yamlDef.ID]; ok && existing.Tier == 1 {
64Ôćĺ					fmt.Fprintf(os.Stderr, "warning: project-local definition for %q ignored (Tier 1 connectors cannot be overridden)\n", yamlDef.ID)
65Ôćĺ					continue
66Ôćĺ				}
67Ôćĺ				defs[yamlDef.ID] = ConnectorDef{
68Ôćĺ					ID:       yamlDef.ID,
69Ôćĺ					Name:     yamlDef.Name,
70Ôćĺ					Type:     yamlDef.Type,
71Ôćĺ					Tier:     yamlDef.Tier,
72Ôćĺ					Required: yamlDef.Required,
73Ôćĺ					Def:      yamlDef,
74Ôćĺ				}
75Ôćĺ			}
76Ôćĺ		}
77Ôćĺ	}
78Ôćĺ
79Ôćĺ	// Convert to sorted slice: email first (required), then crm, then enrichment
80Ôćĺ	typeOrder := map[string]int{"email": 0, "crm": 1, "enrichment": 2, "sequencing": 3, "webhook": 4}
81Ôćĺ	result := make([]ConnectorDef, 0, len(defs))
82Ôćĺ	for _, d := range defs {
83Ôćĺ		result = append(result, d)
84Ôćĺ	}
85Ôćĺ	sort.Slice(result, func(i, j int) bool {
86Ôćĺ		oi := typeOrder[result[i].Type]
87Ôćĺ		oj := typeOrder[result[j].Type]
88Ôćĺ		if oi != oj {
89Ôćĺ			return oi < oj
90Ôćĺ		}
91Ôćĺ		return result[i].Name < result[j].Name
92Ôćĺ	})
93Ôćĺ
94Ôćĺ	return result, nil
95Ôćĺ}
