298Ôćĺfunc readSkillContent(path string) (string, error) {
299Ôćĺ	var data []byte
300Ôćĺ	var err error
301Ôćĺ	if strings.TrimSpace(path) != "" {
302Ôćĺ		data, err = os.ReadFile(path)
303Ôćĺ		if err != nil {
304Ôćĺ			return "", fmt.Errorf("reading skill content: %w", err)
305Ôćĺ		}
306Ôćĺ	} else {
307Ôćĺ		data, err = io.ReadAll(os.Stdin)
308Ôćĺ		if err != nil {
309Ôćĺ			return "", fmt.Errorf("reading stdin: %w", err)
310Ôćĺ		}
311Ôćĺ	}
312Ôćĺ
313Ôćĺ	content := strings.TrimSpace(string(data))
314Ôćĺ	if content == "" {
315Ôćĺ		return "", fmt.Errorf("no skill content provided")
316Ôćĺ	}
317Ôćĺ	return content, nil
318Ôćĺ}
