17Ôćĺvar skillsInstallWrappersCmd = &cobra.Command{
18Ôćĺ	Use:   "install-wrappers",
19Ôćĺ	Short: "Install all 17 thin skill wrappers that invoke nurge context assemble",
20Ôćĺ	Long: `Installs thin SKILL.md wrappers for all 16 skills. Each wrapper invokes
21Ôćĺnurge context assemble with the appropriate task type, then follows the
22Ôćĺassembled instructions. The intelligence lives in knowledge atoms and the
23Ôćĺassembly engine, not in the skill files themselves.
24Ôćĺ
25ÔćĺUse --force to overwrite existing skill files.`,
26Ôćĺ	RunE: func(cmd *cobra.Command, args []string) error {
27Ôćĺ		templates := assembly.ThinSkillTemplates()
