31Ôćĺ		for name, content := range templates {
32Ôćĺ			dir := filepath.Join(".claude", "skills", name)
33Ôćĺ			path := filepath.Join(dir, "SKILL.md")
34Ôćĺ
35Ôćĺ			// Check if skill already exists on disk.
36Ôćĺ			if !installWrappersForce {
37Ôćĺ				if _, err := os.Stat(path); err == nil {
