40Ôćĺ				}
41Ôćĺ			}
42Ôćĺ
43Ôćĺ			if err := os.MkdirAll(dir, 0755); err != nil {
44Ôćĺ				return fmt.Errorf("creating directory %s: %w", dir, err)
45Ôćĺ			}
46Ôćĺ			if err := os.WriteFile(path, []byte(content), 0644); err != nil {
47Ôćĺ				return fmt.Errorf("writing %s: %w", path, err)
48Ôćĺ			}
49Ôćĺ			installed = append(installed, name)
50Ôćĺ		}
51Ôćĺ
52Ôćĺ		// Save versions to DB if available.
53Ôćĺ		d, dbErr := db.Open()
54Ôćĺ		if dbErr == nil {
55Ôćĺ			defer d.Close()
56Ôćĺ			counts, err := session.CurrentSnapshotCounts(d)
57Ôćĺ			if err == nil {
58Ôćĺ				for name, content := range templates {
59Ôćĺ					// Only save versions for skills we actually wrote.
60Ôćĺ					for _, inst := range installed {
61Ôćĺ						if inst == name {
62Ôćĺ							_, _ = session.SaveSkillVersion(d, name, content, counts.EmailCount, counts.LearningCount)
63Ôćĺ							break
64Ôćĺ						}
65Ôćĺ					}
66Ôćĺ				}
67Ôćĺ			}
68Ôćĺ		}
69Ôćĺ
70Ôćĺ		if len(installed) > 0 {
71Ôćĺ			fmt.Printf("Installed %d thin skill wrappers: %s\n", len(installed), strings.Join(installed, ", "))
72Ôćĺ		}
73Ôćĺ		if len(skipped) > 0 {
74Ôćĺ			fmt.Printf("Skipped %d existing skills (use --force to overwrite): %s\n", len(skipped), strings.Join(skipped, ", "))
75Ôćĺ		}
76Ôćĺ		if len(installed) == 0 && len(skipped) == 0 {
77Ôćĺ			fmt.Println("No skill templates available.")
78Ôćĺ		}
79Ôćĺ
