 10Ôćĺtype hooksStep struct{}
 11Ôćĺ
 12Ôćĺfunc (s *hooksStep) Name() string { return "Claude Code hooks installed" }
 13Ôćĺ
 14Ôćĺ// hookEntry is a single hook within a matcher group.
 15Ôćĺ// Exactly one of command or prompt must be set.
 16Ôćĺtype hookEntry struct {
 17Ôćĺ	command string // for type "command"
