 27Ôćĺ
 28Ôćĺ// requiredHookGroups defines all hook groups nurge needs installed.
 29Ôćĺ// Hooks sharing the same event+matcher are grouped together (matching entire.io's pattern).
 30Ôćĺvar requiredHookGroups = []hookGroup{
 31Ôćĺ	{
 32Ôćĺ		event:   "PostToolUse",
 33Ôćĺ		matcher: "Bash",
 34Ôćĺ		hooks:   []hookEntry{{command: "nurge hook post-tool-use"}},
 35Ôćĺ	},
 36Ôćĺ	{
