 38Ôćĺ		matcher: "",
 39Ôćĺ		hooks:   []hookEntry{{command: "nurge hook session-start"}},
 40Ôćĺ	},
 41Ôćĺ	{
 42Ôćĺ		event:   "UserPromptSubmit",
 43Ôćĺ		matcher: "",
 44Ôćĺ		hooks:   []hookEntry{{command: "nurge hook user-prompt"}},
 45Ôćĺ	},
 46Ôćĺ	{
 47Ôćĺ		event:   "Stop",
 48Ôćĺ		matcher: "",
 49Ôćĺ		hooks: []hookEntry{
 50Ôćĺ			{command: "nurge hook stop"},
 51Ôćĺ			{prompt: "Before finishing, capture any new insights from this session. If you learned something about tone preferences, ICP refinements, product positioning, messaging patterns, competitor intel, or user preferences, save each as: nurge learn save --type <type> (types: tone, icp, product, pattern, preference, competitor). Only save non-obvious insights that will help future sessions. Skip if nothing new was learned. Keep each learning to 1-2 sentences."},
 52Ôćĺ		},
 53Ôćĺ	},
 54Ôćĺ	{
