 61Ôćĺfunc (s *hooksStep) Done() (bool, error) {
 62Ôćĺ	data, err := os.ReadFile(claudeSettingsPath())
 63Ôćĺ	if err != nil {
 64Ôćĺ		if os.IsNotExist(err) {
 65Ôćĺ			return false, nil
 66Ôćĺ		}
 67Ôćĺ		return false, err
 68Ôćĺ	}
 69Ôćĺ
 70Ôćĺ	var settings map[string]any
 71Ôćĺ	if err := json.Unmarshal(data, &settings); err != nil {
 72Ôćĺ		return false, nil
 73Ôćĺ	}
 74Ôćĺ
 75Ôćĺ	hooks, ok := settings["hooks"].(map[string]any)
 76Ôćĺ	if !ok {
 77Ôćĺ		return false, nil
 78Ôćĺ	}
 79Ôćĺ
 80Ôćĺ	for _, g := range requiredHookGroups {
 81Ôćĺ		for _, h := range g.hooks {
 82Ôćĺ			if !hookEntryExists(hooks, g.event, h) {
 83Ôćĺ				return false, nil
 84Ôćĺ			}
 85Ôćĺ		}
 86Ôćĺ	}
 87Ôćĺ	return true, nil
 88Ôćĺ}
 89Ôćĺ
 90Ôćĺfunc (s *hooksStep) Run() error {
 91Ôćĺ	settingsPath := claudeSettingsPath()
 92Ôćĺ
 93Ôćĺ	if err := os.MkdirAll(filepath.Dir(settingsPath), 0755); err != nil {
 94Ôćĺ		return fmt.Errorf("creating .claude/: %w", err)
 95Ôćĺ	}
 96Ôćĺ
 97Ôćĺ	// Load existing settings or start fresh
 98Ôćĺ	settings := make(map[string]any)
 99Ôćĺ	if data, err := os.ReadFile(settingsPath); err == nil {
100Ôćĺ		json.Unmarshal(data, &settings) // ignore error, start fresh if corrupt
101Ôćĺ	}
102Ôćĺ
103Ôćĺ	hooks, _ := settings["hooks"].(map[string]any)
104Ôćĺ	if hooks == nil {
105Ôćĺ		hooks = make(map[string]any)
106Ôćĺ	}
107Ôćĺ
108Ôćĺ	for _, g := range requiredHookGroups {
109Ôćĺ		// Collect entries that are missing
110Ôćĺ		var missing []hookEntry
111Ôćĺ		for _, h := range g.hooks {
112Ôćĺ			if !hookEntryExists(hooks, g.event, h) {
113Ôćĺ				missing = append(missing, h)
114Ôćĺ			}
115Ôćĺ		}
116Ôćĺ		if len(missing) == 0 {
117Ôćĺ			continue
118Ôćĺ		}
119Ôćĺ
120Ôćĺ		// Find existing matcher entry for this event+matcher, or create one
121Ôćĺ		eventHooks, _ := hooks[g.event].([]any)
122Ôćĺ		matcherIdx := -1
123Ôćĺ		for i, item := range eventHooks {
124Ôćĺ			m, ok := item.(map[string]any)
125Ôćĺ			if !ok {
126Ôćĺ				continue
127Ôćĺ			}
128Ôćĺ			if matcher, _ := m["matcher"].(string); matcher == g.matcher {
129Ôćĺ				matcherIdx = i
130Ôćĺ				break
131Ôćĺ			}
132Ôćĺ		}
133Ôćĺ
134Ôćĺ		if matcherIdx >= 0 {
135Ôćĺ			entry := eventHooks[matcherIdx].(map[string]any)
136Ôćĺ			innerHooks, _ := entry["hooks"].([]any)
137Ôćĺ			for _, h := range missing {
138Ôćĺ				innerHooks = append(innerHooks, hookEntryToJSON(h))
139Ôćĺ			}
140Ôćĺ			entry["hooks"] = innerHooks
141Ôćĺ		} else {
142Ôćĺ			var innerHooks []any
143Ôćĺ			for _, h := range g.hooks {
144Ôćĺ				innerHooks = append(innerHooks, hookEntryToJSON(h))
145Ôćĺ			}
146Ôćĺ			entry := map[string]any{
147Ôćĺ				"matcher": g.matcher,
148Ôćĺ				"hooks":   innerHooks,
149Ôćĺ			}
150Ôćĺ			eventHooks = append(eventHooks, entry)
151Ôćĺ		}
152Ôćĺ		hooks[g.event] = eventHooks
153Ôćĺ	}
154Ôćĺ
155Ôćĺ	settings["hooks"] = hooks
156Ôćĺ
157Ôćĺ	// Sync permissions into the settings
158Ôćĺ	syncPermissionsInto(settings)
159Ôćĺ
160Ôćĺ	data, err := json.MarshalIndent(settings, "", "  ")
161Ôćĺ	if err != nil {
162Ôćĺ		return fmt.Errorf("marshaling settings: %w", err)
163Ôćĺ	}
164Ôćĺ
165Ôćĺ	if err := os.WriteFile(settingsPath, data, 0644); err != nil {
166Ôćĺ		return fmt.Errorf("writing settings: %w", err)
167Ôćĺ	}
168Ôćĺ
169Ôćĺ	return nil
170Ôćĺ}
171Ôćĺ
172Ôćĺ// hookEntryExists checks if a specific hook entry (command or prompt) already
173Ôćĺ// exists under the given event key.
174Ôćĺfunc hookEntryExists(hooks map[string]any, event string, entry hookEntry) bool {
175Ôćĺ	arr, ok := hooks[event].([]any)
176Ôćĺ	if !ok {
177Ôćĺ		return false
178Ôćĺ	}
179Ôćĺ	for _, item := range arr {
180Ôćĺ		m, ok := item.(map[string]any)
181Ôćĺ		if !ok {
182Ôćĺ			continue
183Ôćĺ		}
184Ôćĺ		innerHooks, ok := m["hooks"].([]any)
185Ôćĺ		if !ok {
186Ôćĺ			continue
187Ôćĺ		}
188Ôćĺ		for _, h := range innerHooks {
189Ôćĺ			hm, ok := h.(map[string]any)
190Ôćĺ			if !ok {
191Ôćĺ				continue
192Ôćĺ			}
193Ôćĺ			if entry.command != "" {
194Ôćĺ				if cmd, ok := hm["command"].(string); ok && cmd == entry.command {
195Ôćĺ					return true
196Ôćĺ				}
197Ôćĺ			}
198Ôćĺ			if entry.prompt != "" {
199Ôćĺ				if p, ok := hm["prompt"].(string); ok && p == entry.prompt {
200Ôćĺ					return true
201Ôćĺ				}
202Ôćĺ			}
203Ôćĺ		}
204Ôćĺ	}
205Ôćĺ	return false
206Ôćĺ}
207Ôćĺ
208Ôćĺ// hookCommandExists is a convenience wrapper for checking command hooks.
209Ôćĺfunc hookCommandExists(hooks map[string]any, event, command string) bool {
210Ôćĺ	return hookEntryExists(hooks, event, hookEntry{command: command})
211Ôćĺ}
212Ôćĺ
213Ôćĺfunc containsString(arr []any, s string) bool {
214Ôćĺ	for _, v := range arr {
215Ôćĺ		if str, ok := v.(string); ok && str == s {
216Ôćĺ			return true
217Ôćĺ		}
218Ôćĺ	}
219Ôćĺ	return false
220Ôćĺ}
221Ôćĺ
222Ôćĺfunc hookEntryToJSON(entry hookEntry) map[string]any {
223Ôćĺ	if entry.prompt != "" {
224Ôćĺ		return map[string]any{"type": "prompt", "prompt": entry.prompt}
225Ôćĺ	}
226Ôćĺ	return map[string]any{"type": "command", "command": entry.command}
227Ôćĺ}
228Ôćĺ
229Ôćĺfunc claudeSettingsPath() string {
230Ôćĺ	return filepath.Join(".claude", "settings.json")
231Ôćĺ}
232Ôćĺ
233Ôćĺ// RequiredPermissions lists all allow-rules nurge needs in .claude/settings.json.
234Ôćĺ// Kept in one place so init and session-start sync stay consistent.
235Ôćĺvar RequiredPermissions = []string{
236Ôćĺ	"Bash(nurge *)",
237Ôćĺ	"Bash(git *)",
238Ôćĺ	"Bash(go *)",
239Ôćĺ	"Bash(curl *)",
240Ôćĺ	"Bash(dig *)",
241Ôćĺ	"Bash(gh *)",
242Ôćĺ	"Bash(which *)",
243Ôćĺ	"Bash(ls *)",
244Ôćĺ	"Bash(mkdir *)",
245Ôćĺ	"Bash(cp *)",
246Ôćĺ	"Bash(mv *)",
247Ôćĺ	"Read",
248Ôćĺ	"Edit",
249Ôćĺ	"Write",
250Ôćĺ	"WebFetch",
251Ôćĺ	"WebSearch",
252Ôćĺ}
253Ôćĺ
254Ôćĺ// syncPermissionsInto ensures all RequiredPermissions are present in the
255Ôćĺ// given settings map (mutates in place).
256Ôćĺfunc syncPermissionsInto(settings map[string]any) {
257Ôćĺ	permissions, _ := settings["permissions"].(map[string]any)
258Ôćĺ	if permissions == nil {
259Ôćĺ		permissions = make(map[string]any)
260Ôćĺ	}
261Ôćĺ	allow, _ := permissions["allow"].([]any)
262Ôćĺ	for _, perm := range RequiredPermissions {
263Ôćĺ		if !containsString(allow, perm) {
264Ôćĺ			allow = append(allow, perm)
265Ôćĺ		}
266Ôćĺ	}
267Ôćĺ	permissions["allow"] = allow
268Ôćĺ	settings["permissions"] = permissions
269Ôćĺ}
270Ôćĺ
271Ôćĺ// SyncPermissions reads .claude/settings.json, adds any missing required
272Ôćĺ// permissions, and writes the file back. Safe to call on every session start.
273Ôćĺ// Returns (added, error) where added is the number of new permissions inserted.
274Ôćĺfunc SyncPermissions() (int, error) {
275Ôćĺ	settingsPath := claudeSettingsPath()
276Ôćĺ
277Ôćĺ	settings := make(map[string]any)
278Ôćĺ	if data, err := os.ReadFile(settingsPath); err == nil {
279Ôćĺ		json.Unmarshal(data, &settings)
280Ôćĺ	} else if os.IsNotExist(err) {
281Ôćĺ		return 0, nil
282Ôćĺ	} else {
283Ôćĺ		return 0, err
284Ôćĺ	}
285Ôćĺ
286Ôćĺ	before := countAllowPermissions(settings)
287Ôćĺ	syncPermissionsInto(settings)
288Ôćĺ	added := countAllowPermissions(settings) - before
289Ôćĺ	if added == 0 {
290Ôćĺ		return 0, nil
291Ôćĺ	}
292Ôćĺ
293Ôćĺ	data, err := json.MarshalIndent(settings, "", "  ")
294Ôćĺ	if err != nil {
295Ôćĺ		return 0, fmt.Errorf("marshaling settings: %w", err)
296Ôćĺ	}
297Ôćĺ	if err := os.WriteFile(settingsPath, data, 0644); err != nil {
298Ôćĺ		return 0, fmt.Errorf("writing settings: %w", err)
299Ôćĺ	}
300Ôćĺ	return added, nil
301Ôćĺ}
302Ôćĺ
303Ôćĺfunc countAllowPermissions(settings map[string]any) int {
304Ôćĺ	permissions, _ := settings["permissions"].(map[string]any)
305Ôćĺ	if permissions == nil {
306Ôćĺ		return 0
307Ôćĺ	}
308Ôćĺ	allow, _ := permissions["allow"].([]any)
309Ôćĺ	return len(allow)
310Ôćĺ}
