 16Ôćĺ		SELECT id, source, email, name, domain, company, title, phone,
 17Ôćĺ			   lead_status, tier, tier_score, industry, funding_stage,
 18Ôćĺ			   company_size, linkedin_url, signals, tech_stack,
 19Ôćĺ			   data_confidence, resolve_source, enriched_at, enrichment_sources
 20Ôćĺ		FROM contacts WHERE email = ?
 21Ôćĺ	`, email).Scan(
 22Ôćĺ		&c.ID, &c.Source, &c.Email, &c.Name, &c.Domain, &c.Company, &c.Title, &c.Phone,
 23Ôćĺ		&c.LeadStatus, &c.Tier, &c.TierScore, &c.Industry, &c.FundingStage,
