 36Ôćĺ// buildScopes derives the atom lookup scopes from a contact.
 37Ôćĺ// More specific scopes come first; QueryAtoms returns best match.
 38Ôćĺfunc buildScopes(contact *Contact) []string {
 39Ôćĺ	if contact == nil {
 40Ôćĺ		return nil
 41Ôćĺ	}
 42Ôćĺ	var scopes []string
 43Ôćĺ	// Persona/title scope
 44Ôćĺ	if contact.Title != "" {
 45Ôćĺ		scopes = append(scopes, normalizeScope(contact.Title))
 46Ôćĺ	}
 47Ôćĺ	// Tier scope
 48Ôćĺ	if contact.Tier > 0 {
 49Ôćĺ		scopes = append(scopes, fmt.Sprintf("tier_%d", contact.Tier))
 50Ôćĺ	}
 51Ôćĺ	// Industry scope
 52Ôćĺ	if contact.Industry != "" {
 53Ôćĺ		scopes = append(scopes, normalizeScope(contact.Industry))
 54Ôćĺ	}
 55Ôćĺ	// Domain scope (for company-specific atoms)
 56Ôćĺ	if contact.Domain != "" {
 57Ôćĺ		scopes = append(scopes, contact.Domain)
 58Ôćĺ	}
 59Ôćĺ	return scopes
 60Ôćĺ}
