110Ôćĺ// pickBestAtom selects the most relevant atom from candidates.
111Ôćĺ// It prefers scoped matches over the global fallback. Among scoped matches,
112Ôćĺ// it picks the one whose scope appears earliest in the scopes list
113Ôćĺ// (most specific first). Falls back to confidence/recency ordering.
114Ôćĺfunc pickBestAtom(atoms []KnowledgeAtom, scopes []string) KnowledgeAtom {
115Ôćĺ	if len(atoms) == 1 {
116Ôćĺ		return atoms[0]
117Ôćĺ	}
118Ôćĺ
119Ôćĺ	// Build scope priority: lower index = higher priority
120Ôćĺ	scopePrio := make(map[string]int, len(scopes))
121Ôćĺ	for i, s := range scopes {
122Ôćĺ		scopePrio[s] = i
123Ôćĺ	}
124Ôćĺ
125Ôćĺ	best := atoms[0]
126Ôćĺ	bestPrio := len(scopes) + 1 // global ("") gets worst priority
127Ôćĺ	if p, ok := scopePrio[best.Scope]; ok {
128Ôćĺ		bestPrio = p
129Ôćĺ	}
130Ôćĺ
131Ôćĺ	for _, a := range atoms[1:] {
132Ôćĺ		prio := len(scopes) + 1
133Ôćĺ		if p, ok := scopePrio[a.Scope]; ok {
134Ôćĺ			prio = p
135Ôćĺ		}
136Ôćĺ		if prio < bestPrio {
137Ôćĺ			best = a
138Ôćĺ			bestPrio = prio
139Ôćĺ		}
140Ôćĺ	}
141Ôćĺ	return best
142Ôćĺ}
