166Ôćĺ// extractContent tries to pretty-print JSON content; falls back to raw string.
167Ôćĺfunc extractContent(raw json.RawMessage) string {
168Ôćĺ	// Try to unmarshal as a string first (common for text atoms)
169Ôćĺ	var s string
170Ôćĺ	if err := json.Unmarshal(raw, &s); err == nil {
171Ôćĺ		return s
172Ôćĺ	}
173Ôćĺ	// Return formatted JSON for structured atoms
174Ôćĺ	var pretty json.RawMessage
175Ôćĺ	if err := json.Unmarshal(raw, &pretty); err == nil {
176Ôćĺ		indented, err := json.MarshalIndent(pretty, "", "  ")
177Ôćĺ		if err == nil {
178Ôćĺ			return string(indented)
179Ôćĺ		}
180Ôćĺ	}
181Ôćĺ	return string(raw)
182Ôćĺ}
