221Ôćĺ// queryLearningsByTypes fetches learnings, optionally filtered by type, newest first.
222Ôćĺfunc queryLearningsByTypes(database *sql.DB, types []string, limit int) ([]Learning, error) {
223Ôćĺ	var query string
224Ôćĺ	var args []any
225Ôćĺ
226Ôćĺ	if len(types) == 0 {
227Ôćĺ		query = `SELECT id, type, content, source_session, created_at FROM learnings ORDER BY created_at DESC LIMIT ?`
228Ôćĺ		args = append(args, limit)
229Ôćĺ	} else {
230Ôćĺ		placeholders := make([]string, len(types))
231Ôćĺ		for i, t := range types {
232Ôćĺ			placeholders[i] = "?"
233Ôćĺ			args = append(args, t)
234Ôćĺ		}
235Ôćĺ		query = fmt.Sprintf(
236Ôćĺ			`SELECT id, type, content, source_session, created_at FROM learnings WHERE type IN (%s) ORDER BY created_at DESC LIMIT ?`,
237Ôćĺ			strings.Join(placeholders, ","),
238Ôćĺ		)
239Ôćĺ		args = append(args, limit)
240Ôćĺ	}
241Ôćĺ
242Ôćĺ	rows, err := database.Query(query, args...)
243Ôćĺ	if err != nil {
244Ôćĺ		return nil, fmt.Errorf("querying learnings: %w", err)
245Ôćĺ	}
246Ôćĺ	defer rows.Close()
247Ôćĺ
248Ôćĺ	var learnings []Learning
249Ôćĺ	for rows.Next() {
250Ôćĺ		var l Learning
251Ôćĺ		if err := rows.Scan(&l.ID, &l.Type, &l.Content, &l.SourceSession, &l.CreatedAt); err != nil {
252Ôćĺ			return nil, fmt.Errorf("scanning learning: %w", err)
253Ôćĺ		}
254Ôćĺ		learnings = append(learnings, l)
255Ôćĺ	}
256Ôćĺ	return learnings, rows.Err()
257Ôćĺ}
