259Ôćĺ// loadConfigContext reads project config and returns relevant context for the task.
260Ôćĺfunc loadConfigContext(task TaskType) string {
261Ôćĺ	cfg, err := project.Load()
262Ôćĺ	if err != nil {
263Ôćĺ		return ""
264Ôćĺ	}
265Ôćĺ
266Ôćĺ	var lines []string
267Ôćĺ
268Ôćĺ	// Show connected services
269Ôćĺ	if len(cfg.Connectors) > 0 {
270Ôćĺ		var connected []string
271Ôćĺ		for id, c := range cfg.Connectors {
272Ôćĺ			if c.Connected {
273Ôćĺ				connected = append(connected, id)
274Ôćĺ			}
275Ôćĺ		}
276Ôćĺ		if len(connected) > 0 {
277Ôćĺ			lines = append(lines, fmt.Sprintf("**Connected services:** %s", strings.Join(connected, ", ")))
278Ôćĺ		}
279Ôćĺ	}
280Ôćĺ
281Ôćĺ	// Show relevant settings
282Ôćĺ	if cfg.Settings != nil {
