295Ôćĺ		}
296Ôćĺ		if v, ok := cfg.Settings["icp.company_size"]; ok && v != "" {
297Ôćĺ			lines = append(lines, fmt.Sprintf("**ICP Company Size:** %s", v))
298Ôćĺ		}
299Ôćĺ		if v, ok := cfg.Settings["sender.name"]; ok && v != "" {
