301Ôćĺ		}
302Ôćĺ		if v, ok := cfg.Settings["sender.email"]; ok && v != "" {
303Ôćĺ			lines = append(lines, fmt.Sprintf("**From:** %s", v))
304Ôćĺ		}
305Ôćĺ
306Ôćĺ		// Task-specific settings
307Ôćĺ		switch task {
308Ôćĺ		case TaskHygiene, TaskSendHealth:
309Ôćĺ			if v, ok := cfg.Settings["sending.daily_cap"]; ok && v != "" {
310Ôćĺ				lines = append(lines, fmt.Sprintf("**Daily Cap:** %s", v))
