314Ôćĺ				lines = append(lines, fmt.Sprintf("**Default Sequence:** %s", v))
315Ôćĺ			}
316Ôćĺ		}
317Ôćĺ	}
318Ôćĺ
319Ôćĺ	if len(lines) == 0 {
320Ôćĺ		return ""
321Ôćĺ	}
322Ôćĺ	return strings.Join(lines, "\n")
323Ôćĺ}
