325Ôćĺ// estimateTokens does a rough word count * 1.3 approximation.
326Ôćĺfunc estimateTokens(text string) int {
327Ôćĺ	words := len(strings.Fields(text))
328Ôćĺ	return int(float64(words) * 1.3)
