 69Ôćĺ			tokenDir := fmt.Sprintf(".nurge/connectors/%s", id)
 70Ôćĺ			_ = os.RemoveAll(tokenDir)
 71Ôćĺ		}
 72Ôćĺ		cleanup, err := acquireConnectLock(id)
 73Ôćĺ		if err != nil {
