36Ôćĺ		// 1.5. Reset sync cursor in DB so reconnect gets fresh sync (best effort)
37Ôćĺ		if d, dbErr := db.Open(); dbErr == nil {
38Ôćĺ			defer d.Close()
39Ôćĺ			d.Exec("DELETE FROM connectors WHERE id = ? OR id = ?", id, id+"-convex")
40Ôćĺ		}
41Ôćĺ
42Ôćĺ		// 2. Notify server for Convex-backed connectors (best effort)
43Ôćĺ		if id == "gmail" || id == "linkedin" {
44Ôćĺ			af, err := account.LoadAuth()
45Ôćĺ			if err == nil && af.Token != "" {
46Ôćĺ				client := account.NewConvexClient(cmdutil.GetConvexURL())
47Ôćĺ				providerMap := map[string]string{"gmail": "GOOGLE", "linkedin": "LINKEDIN"}
48Ôćĺ				if err := client.DisconnectProvider(af.Token, providerMap[id]); err != nil {
49Ôćĺ					fmt.Fprintf(os.Stderr, "  warning: could not notify server: %v\n", err)
50Ôćĺ				}
51Ôćĺ			}
52Ôćĺ		}
53Ôćĺ
54Ôćĺ		// 3. Delete token files (best effort, config already updated)
55Ôćĺ		tokenDir := fmt.Sprintf(".nurge/connectors/%s", id)
56Ôćĺ		if err := os.RemoveAll(tokenDir); err != nil {
57Ôćĺ			fmt.Fprintf(os.Stderr, "  warning: could not remove %s: %v\n", tokenDir, err)
58Ôćĺ		}
59Ôćĺ
60Ôćĺ		fmt.Printf("\033[32mÔťô\033[0m %s disconnected\n", id)
61Ôćĺ		return nil
62Ôćĺ	},
63Ôćĺ}
