 13Ôćĺfunc (g *GenericConnector) connectOAuth2(ctx context.Context) (*Result, error) {
 14Ôćĺ	var oauthCfg *oauth2.Config
 15Ôćĺ	var authOpts []oauth2.AuthCodeOption
 16Ôćĺ
 17Ôćĺ	if g.def.Credentials.Source == "google_json" {
 18Ôćĺ		// Google-specific: use google.ConfigFromJSON
 19Ôćĺ		credsData, err := g.loadGoogleCredentials()
 20Ôćĺ		if err != nil {
 21Ôćĺ			return nil, err
 22Ôćĺ		}
 23Ôćĺ		cfg, err := google.ConfigFromJSON(credsData, g.def.Auth.Scopes...)
 24Ôćĺ		if err != nil {
 25Ôćĺ			return nil, fmt.Errorf("parsing Google credentials: %w", err)
 26Ôćĺ		}
 27Ôćĺ		oauthCfg = cfg
 28Ôćĺ	} else {
 29Ôćĺ		// Generic OAuth2: build config from YAML
 30Ôćĺ		clientID, clientSecret, err := g.resolveOAuthCredentials()
 31Ôćĺ		if err != nil {
 32Ôćĺ			return nil, err
 33Ôćĺ		}
 34Ôćĺ		cfg, opts, err := g.buildOAuthConfig(clientID, clientSecret)
 35Ôćĺ		if err != nil {
 36Ôćĺ			return nil, err
 37Ôćĺ		}
 38Ôćĺ		oauthCfg = cfg
 39Ôćĺ		authOpts = opts
 40Ôćĺ	}
 41Ôćĺ
 42Ôćĺ	// Add extra_params as auth options for google_json too
 43Ôćĺ	if g.def.Credentials.Source == "google_json" {
 44Ôćĺ		for k, v := range g.def.Auth.ExtraParams {
 45Ôćĺ			authOpts = append(authOpts, oauth2.SetAuthURLParam(k, v))
 46Ôćĺ		}
 47Ôćĺ	}
 48Ôćĺ
 49Ôćĺ	// Run shared OAuth flow
 50Ôćĺ	token, err := OAuthFlow(ctx, oauthCfg, authOpts...)
 51Ôćĺ	if err != nil {
 52Ôćĺ		return nil, err
 53Ôćĺ	}
 54Ôćĺ
 55Ôćĺ	// Save token
 56Ôćĺ	tokenDir := fmt.Sprintf(".nurge/connectors/%s", g.def.ID)
 57Ôćĺ	tokenPath := tokenDir + "/token.json"
 58Ôćĺ	if err := os.MkdirAll(tokenDir, 0700); err != nil {
 59Ôćĺ		return nil, fmt.Errorf("creating connector dir: %w", err)
 60Ôćĺ	}
 61Ôćĺ	if err := saveToken(tokenPath, token); err != nil {
 62Ôćĺ		return nil, fmt.Errorf("saving token: %w", err)
 63Ôćĺ	}
 64Ôćĺ
 65Ôćĺ	// Save granted scopes for later scope-sufficiency checks
 66Ôćĺ	if len(g.def.Auth.Scopes) > 0 {
 67Ôćĺ		_ = SaveGrantedScopes(tokenDir, g.def.Auth.Scopes)
 68Ôćĺ	}
 69Ôćĺ
 70Ôćĺ	// Verify connection + get account identifier
 71Ôćĺ	account, err := g.runVerify(ctx, oauthCfg, token)
 72Ôćĺ	if err != nil {
 73Ôćĺ		// Non-fatal: connected but can't verify
 74Ôćĺ		account = "connected (unverified)"
 75Ôćĺ	}
 76Ôćĺ
 77Ôćĺ	return &Result{
 78Ôćĺ		Account: account,
 79Ôćĺ		Token:   token,
 80Ôćĺ	}, nil
 81Ôćĺ}
