193Ôćĺ// resolveOAuthCredentials reads client ID and secret from the configured source.
194Ôćĺfunc (g *GenericConnector) resolveOAuthCredentials() (string, string, error) {
195Ôćĺ	cred := g.def.Credentials
196Ôćĺ
197Ôćĺ	switch cred.Source {
198Ôćĺ	case "env":
199Ôćĺ		id := os.Getenv(cred.ClientIDVar)
200Ôćĺ		secret := os.Getenv(cred.ClientSecretVar)
201Ôćĺ		if id == "" || secret == "" {
202Ôćĺ			return "", "", fmt.Errorf("%s credentials not configured.\n  Set %s and %s environment variables",
203Ôćĺ				g.def.Name, cred.ClientIDVar, cred.ClientSecretVar)
204Ôćĺ		}
205Ôćĺ		return id, secret, nil
206Ôćĺ
207Ôćĺ	case "prompt":
208Ôćĺ		if fi, err := os.Stdin.Stat(); err != nil || fi.Mode()&os.ModeCharDevice == 0 {
209Ôćĺ			return "", "", fmt.Errorf("%s requires interactive input for credentials. Set environment variables or use a credentials file instead", g.def.Name)
210Ôćĺ		}
211Ôćĺ		var id, secret string
212Ôćĺ		fmt.Printf("Enter %s client ID: ", g.def.Name)
213Ôćĺ		fmt.Scanln(&id)
214Ôćĺ		fmt.Printf("Enter %s client secret: ", g.def.Name)
215Ôćĺ		fmt.Scanln(&secret)
216Ôćĺ		if id == "" || secret == "" {
217Ôćĺ			return "", "", fmt.Errorf("client ID and secret are required")
218Ôćĺ		}
219Ôćĺ		return id, secret, nil
220Ôćĺ
221Ôćĺ	default:
222Ôćĺ		return "", "", fmt.Errorf("unsupported credential source %q for connector %s", cred.Source, g.def.ID)
223Ôćĺ	}
224Ôćĺ}
