  1Ôćĺpackage enrich
  2Ôćĺ
  3Ôćĺimport (
  4Ôćĺ	"database/sql"
  5Ôćĺ	"encoding/json"
  6Ôćĺ	"fmt"
  7Ôćĺ	"log"
  8Ôćĺ	"strings"
  9Ôćĺ	"time"
 10Ôćĺ
 11Ôćĺ	"github.com/usenurge/nurgesh/internal/assembly"
 12Ôćĺ)
 13Ôćĺ
 14Ôćĺ// Enrich enriches a single contact, filling missing fields via the waterfall.
 15Ôćĺfunc Enrich(db *sql.DB, req EnrichRequest) (*EnrichResult, error) {
 16Ôćĺ	if req.ContactEmail == "" {
 17Ôćĺ		return nil, fmt.Errorf("contact email is required")
 18Ôćĺ	}
 19Ôćĺ
 20Ôćĺ	// Load provider registry
 21Ôćĺ	registry, err := LoadProviders()
 22Ôćĺ	if err != nil {
 23Ôćĺ		return nil, fmt.Errorf("loading providers: %w", err)
 24Ôćĺ	}
 25Ôćĺ
 26Ôćĺ	// Load contact from DB
 27Ôćĺ	contact, err := loadContact(db, req.ContactEmail)
 28Ôćĺ	if err != nil {
 29Ôćĺ		return nil, fmt.Errorf("loading contact %s: %w", req.ContactEmail, err)
 30Ôćĺ	}
 31Ôćĺ
 32Ôćĺ	// Determine which fields need enrichment
 33Ôćĺ	currentValues := contact.fieldMap()
 34Ôćĺ	var targetFields []string
 35Ôćĺ	if len(req.Fields) > 0 {
 36Ôćĺ		targetFields = req.Fields
 37Ôćĺ	} else {
 38Ôćĺ		targetFields = AllEnrichableFields()
 39Ôćĺ	}
 40Ôćĺ
 41Ôćĺ	var missingFields []string
 42Ôćĺ	for _, f := range targetFields {
 43Ôćĺ		if val, ok := currentValues[f]; !ok || val == "" {
 44Ôćĺ			missingFields = append(missingFields, f)
 45Ôćĺ		}
 46Ôćĺ	}
 47Ôćĺ
 48Ôćĺ	result := &EnrichResult{
 49Ôćĺ		ContactEmail: req.ContactEmail,
 50Ôćĺ		FieldsFilled: make(map[string]string),
 51Ôćĺ	}
 52Ôćĺ
 53Ôćĺ	if len(missingFields) == 0 {
 54Ôćĺ		return result, nil
 55Ôćĺ	}
 56Ôćĺ
 57Ôćĺ	providersUsedSet := make(map[string]bool)
 58Ôćĺ
 59Ôćĺ	// For each missing field, try providers in waterfall order
 60Ôćĺ	for _, field := range missingFields {
 61Ôćĺ		var providerNames []string
 62Ôćĺ		if len(req.Providers) > 0 {
 63Ôćĺ			// Use explicitly requested providers
 64Ôćĺ			providerNames = req.Providers
 65Ôćĺ		} else {
 66Ôćĺ			// Use default waterfall
 67Ôćĺ			providerNames = WaterfallForField(field)
 68Ôćĺ		}
 69Ôćĺ
 70Ôćĺ		filled := false
 71Ôćĺ		for _, provName := range providerNames {
 72Ôćĺ			provider, ok := registry.GetProvider(provName)
 73Ôćĺ			if !ok {
 74Ôćĺ				continue
 75Ôćĺ			}
 76Ôćĺ
 77Ôćĺ			// Check if this provider can fill this field
 78Ôćĺ			canFill := false
 79Ôćĺ			for _, pf := range provider.FieldsProvided {
 80Ôćĺ				if pf == field {
 81Ôćĺ					canFill = true
 82Ôćĺ					break
 83Ôćĺ				}
 84Ôćĺ			}
 85Ôćĺ			if !canFill {
 86Ôćĺ				continue
 87Ôćĺ			}
 88Ôćĺ
 89Ôćĺ			// Build cache key from provider + contact input
 90Ôćĺ			cacheInput := buildCacheInput(provider, contact)
 91Ôćĺ			cacheKey, err := assembly.CacheKey(provName, cacheInput)
 92Ôćĺ			if err != nil {
 93Ôćĺ				continue
 94Ôćĺ			}
 95Ôćĺ
 96Ôćĺ			// Check cache first
 97Ôćĺ			cached, err := assembly.GetCached(db, provName, cacheKey)
 98Ôćĺ			if err != nil {
 99Ôćĺ				log.Printf("cache lookup error for %s/%s: %v", provName, field, err)
100Ôćĺ				continue
101Ôćĺ			}
102Ôćĺ
103Ôćĺ			if cached != nil {
104Ôćĺ				// Extract field value from cached output
105Ôćĺ				var outputMap map[string]string
106Ôćĺ				if err := json.Unmarshal(cached.OutputData, &outputMap); err == nil {
107Ôćĺ					if val, ok := outputMap[field]; ok && val != "" {
108Ôćĺ						result.FieldsFilled[field] = val
109Ôćĺ						result.Cached++
110Ôćĺ						providersUsedSet[provName] = true
111Ôćĺ						filled = true
112Ôćĺ						break
113Ôćĺ					}
114Ôćĺ				}
115Ôćĺ			}
116Ôćĺ
117Ôćĺ			// Not cached -- this is where a real API call would go.
118Ôćĺ			// For now, log what WOULD happen and leave the field missing.
119Ôćĺ			log.Printf("enrich: would call provider %q (type=%s) to fill %q for %s",
120Ôćĺ				provName, provider.Type, field, req.ContactEmail)
121Ôćĺ			result.TotalCost += provider.CostPerCall
122Ôćĺ			providersUsedSet[provName] = true
123Ôćĺ		}
124Ôćĺ
125Ôćĺ		if !filled {
126Ôćĺ			result.FieldsMissing = append(result.FieldsMissing, field)
127Ôćĺ		}
128Ôćĺ	}
129Ôćĺ
130Ôćĺ	// Collect providers used
131Ôćĺ	for p := range providersUsedSet {
132Ôćĺ		result.ProvidersUsed = append(result.ProvidersUsed, p)
133Ôćĺ	}
134Ôćĺ
135Ôćĺ	// Update contacts table with any filled fields
136Ôćĺ	if len(result.FieldsFilled) > 0 {
137Ôćĺ		if err := updateContactFields(db, req.ContactEmail, result.FieldsFilled, result.ProvidersUsed); err != nil {
138Ôćĺ			return result, fmt.Errorf("updating contact: %w", err)
139Ôćĺ		}
140Ôćĺ	}
141Ôćĺ
142Ôćĺ	return result, nil
143Ôćĺ}
144Ôćĺ
145Ôćĺ// BatchEnrich finds unenriched contacts and enriches them.
146Ôćĺfunc BatchEnrich(db *sql.DB, limit int) ([]EnrichResult, error) {
147Ôćĺ	rows, err := db.Query(`
148Ôćĺ		SELECT email FROM contacts
149Ôćĺ		WHERE enriched_at = '' OR enriched_at IS NULL
150Ôćĺ		ORDER BY created_at DESC
151Ôćĺ		LIMIT ?
152Ôćĺ	`, limit)
153Ôćĺ	if err != nil {
154Ôćĺ		return nil, fmt.Errorf("querying unenriched contacts: %w", err)
155Ôćĺ	}
156Ôćĺ	defer rows.Close()
157Ôćĺ
158Ôćĺ	var emails []string
159Ôćĺ	for rows.Next() {
160Ôćĺ		var email string
161Ôćĺ		if err := rows.Scan(&email); err != nil {
162Ôćĺ			continue
163Ôćĺ		}
164Ôćĺ		emails = append(emails, email)
165Ôćĺ	}
166Ôćĺ	if err := rows.Err(); err != nil {
167Ôćĺ		return nil, fmt.Errorf("scanning unenriched contacts: %w", err)
168Ôćĺ	}
169Ôćĺ
170Ôćĺ	var results []EnrichResult
171Ôćĺ	for _, email := range emails {
172Ôćĺ		r, err := Enrich(db, EnrichRequest{ContactEmail: email})
173Ôćĺ		if err != nil {
174Ôćĺ			log.Printf("enrich: skipping %s: %v", email, err)
175Ôćĺ			continue
176Ôćĺ		}
177Ôćĺ		results = append(results, *r)
178Ôćĺ	}
179Ôćĺ
180Ôćĺ	return results, nil
181Ôćĺ}
