183Ôćĺ// Stats returns enrichment coverage across all contacts.
184Ôćĺfunc Stats(db *sql.DB) (*EnrichStats, error) {
185Ôćĺ	stats := &EnrichStats{
186Ôćĺ		FieldCoverage: make(map[string]int),
187Ôćĺ	}
188Ôćĺ
189Ôćĺ	// Total contacts
190Ôćĺ	if err := db.QueryRow(`SELECT COUNT(*) FROM contacts`).Scan(&stats.TotalContacts); err != nil {
191Ôćĺ		return nil, fmt.Errorf("counting contacts: %w", err)
192Ôćĺ	}
193Ôćĺ
194Ôćĺ	// Enriched contacts (have enriched_at set)
195Ôćĺ	if err := db.QueryRow(`SELECT COUNT(*) FROM contacts WHERE enriched_at != '' AND enriched_at IS NOT NULL`).Scan(&stats.Enriched); err != nil {
196Ôćĺ		return nil, fmt.Errorf("counting enriched contacts: %w", err)
197Ôćĺ	}
198Ôćĺ	stats.Unenriched = stats.TotalContacts - stats.Enriched
199Ôćĺ
200Ôćĺ	// Per-field coverage
201Ôćĺ	fieldColumns := map[string]string{
202Ôćĺ		"email":         "email",
203Ôćĺ		"name":          "name",
204Ôćĺ		"title":         "title",
205Ôćĺ		"company":       "company",
206Ôćĺ		"phone":         "phone",
207Ôćĺ		"industry":      "industry",
208Ôćĺ		"company_size":  "company_size",
209Ôćĺ		"funding_stage": "funding_stage",
210Ôćĺ		"website":       "website",
211Ôćĺ		"linkedin_url":  "linkedin_url",
212Ôćĺ	}
213Ôćĺ	for field, col := range fieldColumns {
214Ôćĺ		var count int
215Ôćĺ		query := fmt.Sprintf(`SELECT COUNT(*) FROM contacts WHERE %s != '' AND %s IS NOT NULL`, col, col)
216Ôćĺ		if err := db.QueryRow(query).Scan(&count); err != nil {
217Ôćĺ			continue
218Ôćĺ		}
219Ôćĺ		stats.FieldCoverage[field] = count
220Ôćĺ	}
221Ôćĺ
222Ôćĺ	return stats, nil
223Ôćĺ}
