225Ôćĺ// loadContact reads a contact from the DB.
226Ôćĺfunc loadContact(db *sql.DB, email string) (*contactRow, error) {
227Ôćĺ	c := &contactRow{}
228Ôćĺ	err := db.QueryRow(`
229Ôćĺ		SELECT email, name, title, company, phone, domain,
230Ôćĺ		       COALESCE(industry, ''), COALESCE(company_size, ''),
231Ôćĺ		       COALESCE(funding_stage, ''), COALESCE(linkedin_url, ''),
232Ôćĺ		       COALESCE(website, ''), COALESCE(enriched_at, ''),
233Ôćĺ		       COALESCE(enrichment_sources, '[]')
234Ôćĺ		FROM contacts WHERE email = ?
235Ôćĺ	`, email).Scan(
236Ôćĺ		&c.Email, &c.Name, &c.Title, &c.Company, &c.Phone, &c.Domain,
237Ôćĺ		&c.Industry, &c.CompanySize, &c.FundingStage, &c.LinkedInURL,
238Ôćĺ		&c.Website, &c.EnrichedAt, &c.Sources,
239Ôćĺ	)
240Ôćĺ	if err == sql.ErrNoRows {
241Ôćĺ		return nil, fmt.Errorf("contact not found: %s", email)
242Ôćĺ	}
243Ôćĺ	if err != nil {
244Ôćĺ		return nil, err
245Ôćĺ	}
246Ôćĺ	return c, nil
247Ôćĺ}
