249Ôćĺ// fieldMap returns current non-empty field values.
250Ôćĺfunc (c *contactRow) fieldMap() map[string]string {
251Ôćĺ	return map[string]string{
252Ôćĺ		"email":         c.Email,
253Ôćĺ		"name":          c.Name,
254Ôćĺ		"title":         c.Title,
255Ôćĺ		"company":       c.Company,
256Ôćĺ		"phone":         c.Phone,
257Ôćĺ		"industry":      c.Industry,
258Ôćĺ		"company_size":  c.CompanySize,
259Ôćĺ		"funding_stage": c.FundingStage,
260Ôćĺ		"website":       c.Website,
261Ôćĺ		"linkedin_url":  c.LinkedInURL,
262Ôćĺ	}
263Ôćĺ}
264Ôćĺ
265Ôćĺ// buildCacheInput constructs the input data for cache key generation
266Ôćĺ// based on the provider's input_type and the contact's available data.
267Ôćĺfunc buildCacheInput(provider Provider, contact *contactRow) map[string]string {
268Ôćĺ	input := make(map[string]string)
269Ôćĺ	switch provider.InputType {
270Ôćĺ	case "email":
271Ôćĺ		input["email"] = contact.Email
272Ôćĺ	case "linkedin_url":
273Ôćĺ		input["linkedin_url"] = contact.LinkedInURL
274Ôćĺ	case "name_company":
275Ôćĺ		input["name"] = contact.Name
276Ôćĺ		input["company"] = contact.Company
277Ôćĺ	case "domain":
278Ôćĺ		input["domain"] = contact.Domain
279Ôćĺ	}
280Ôćĺ	return input
281Ôćĺ}
282Ôćĺ
283Ôćĺ// updateContactFields writes filled fields back to the contacts table
284Ôćĺ// and updates enriched_at and enrichment_sources.
285Ôćĺfunc updateContactFields(db *sql.DB, email string, fields map[string]string, providers []string) error {
286Ôćĺ	var setClauses []string
287Ôćĺ	var args []any
288Ôćĺ
289Ôćĺ	for field, value := range fields {
290Ôćĺ		col, ok := enrichableColumns[field]
291Ôćĺ		if !ok {
292Ôćĺ			continue
293Ôćĺ		}
294Ôćĺ		setClauses = append(setClauses, fmt.Sprintf("%s = ?", col))
295Ôćĺ		args = append(args, value)
296Ôćĺ	}
297Ôćĺ
298Ôćĺ	if len(setClauses) == 0 {
299Ôćĺ		return nil
300Ôćĺ	}
301Ôćĺ
302Ôćĺ	// Update enriched_at
303Ôćĺ	setClauses = append(setClauses, "enriched_at = ?")
304Ôćĺ	args = append(args, time.Now().UTC().Format("2006-01-02 15:04:05"))
305Ôćĺ
306Ôćĺ	// Merge enrichment_sources
307Ôćĺ	sourcesJSON, _ := json.Marshal(providers)
308Ôćĺ	setClauses = append(setClauses, "enrichment_sources = ?")
309Ôćĺ	args = append(args, string(sourcesJSON))
310Ôćĺ
311Ôćĺ	// updated_at
312Ôćĺ	setClauses = append(setClauses, "updated_at = datetime('now')")
313Ôćĺ
314Ôćĺ	args = append(args, email)
315Ôćĺ
316Ôćĺ	query := fmt.Sprintf("UPDATE contacts SET %s WHERE email = ?", strings.Join(setClauses, ", "))
317Ôćĺ	_, err := db.Exec(query, args...)
318Ôćĺ	return err
319Ôćĺ}
