  9Ôćĺ	"gopkg.in/yaml.v3"
 10Ôćĺ)
 11Ôćĺ
 12Ôćĺ// Provider defines an enrichment data source loaded from YAML.
 13Ôćĺtype Provider struct {
 14Ôćĺ	Name           string            `yaml:"name"`
 15Ôćĺ	Type           string            `yaml:"provider"` // apify, apollo, http
 16Ôćĺ	Endpoint       string            `yaml:"endpoint,omitempty"`
 17Ôćĺ	ActorID        string            `yaml:"actor_id,omitempty"`
 18Ôćĺ	CostPerCall    float64           `yaml:"cost_per_call"`
 19Ôćĺ	FieldsProvided []string          `yaml:"fields_provided"`
 20Ôćĺ	InputType      string            `yaml:"input_type"` // email, linkedin_url, name_company, domain
 21Ôćĺ	InputMapping   map[string]string `yaml:"input_mapping"`
 22Ôćĺ	OutputMapping  map[string]string `yaml:"output_mapping"`
 23Ôćĺ	CacheTTL       string            `yaml:"cache_ttl"` // e.g., "168h"
 24Ôćĺ}
 25Ôćĺ
 26Ôćĺ// ProviderRegistry holds all loaded providers keyed by name.
 27Ôćĺtype ProviderRegistry struct {
 28Ôćĺ	providers map[string]Provider
 29Ôćĺ}
 30Ôćĺ
 31Ôćĺ// LoadProviders scans bundled provider YAMLs from internal/enrich/providers/
 32Ôćĺ// and user-defined YAMLs from .nurge/providers/. User definitions override
 33Ôćĺ// bundled ones by name.
 34Ôćĺfunc LoadProviders() (*ProviderRegistry, error) {
 35Ôćĺ	reg := &ProviderRegistry{
 36Ôćĺ		providers: make(map[string]Provider),
 37Ôćĺ	}
 38Ôćĺ
 39Ôćĺ	// 1. Load bundled providers (currently none -- Apify/Apollo YAMLs were
 40Ôćĺ	// removed as dead code; enrichment now uses Convex/Unipile).
 41Ôćĺ	entries, err := fs.ReadDir(bundledProviders, "providers")
 42Ôćĺ	if err == nil {
 43Ôćĺ		for _, entry := range entries {
 44Ôćĺ			if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".yaml") {
 45Ôćĺ				continue
 46Ôćĺ			}
 47Ôćĺ			data, readErr := fs.ReadFile(bundledProviders, "providers/"+entry.Name())
 48Ôćĺ			if readErr != nil {
 49Ôćĺ				continue
 50Ôćĺ			}
 51Ôćĺ			var p Provider
 52Ôćĺ			if err := yaml.Unmarshal(data, &p); err != nil {
 53Ôćĺ				continue // skip invalid bundled defs
 54Ôćĺ			}
 55Ôćĺ			if p.Name == "" {
 56Ôćĺ				continue
 57Ôćĺ			}
 58Ôćĺ			reg.providers[p.Name] = p
 59Ôćĺ		}
 60Ôćĺ	}
 61Ôćĺ
 62Ôćĺ	// 2. Load project-local providers from .nurge/providers/
 63Ôćĺ	localDir := filepath.Join(".nurge", "providers")
 64Ôćĺ	localEntries, err := os.ReadDir(localDir)
 65Ôćĺ	if err == nil { // silently skip if dir doesn't exist
 66Ôćĺ		for _, entry := range localEntries {
 67Ôćĺ			if entry.IsDir() || !strings.HasSuffix(entry.Name(), ".yaml") {
 68Ôćĺ				continue
 69Ôćĺ			}
 70Ôćĺ			data, err := os.ReadFile(filepath.Join(localDir, entry.Name()))
 71Ôćĺ			if err != nil {
 72Ôćĺ				continue
 73Ôćĺ			}
 74Ôćĺ			var p Provider
 75Ôćĺ			if err := yaml.Unmarshal(data, &p); err != nil {
 76Ôćĺ				continue
 77Ôćĺ			}
 78Ôćĺ			if p.Name == "" {
 79Ôćĺ				continue
 80Ôćĺ			}
 81Ôćĺ			reg.providers[p.Name] = p
 82Ôćĺ		}
 83Ôćĺ	}
 84Ôćĺ
 85Ôćĺ	return reg, nil
 86Ôćĺ}
 87Ôćĺ
 88Ôćĺ// GetProvider returns a provider by name, or false if not found.
 89Ôćĺfunc (r *ProviderRegistry) GetProvider(name string) (Provider, bool) {
 90Ôćĺ	p, ok := r.providers[name]
 91Ôćĺ	return p, ok
 92Ôćĺ}
 93Ôćĺ
 94Ôćĺ// ProvidersForField returns all providers that can fill a given field.
 95Ôćĺfunc (r *ProviderRegistry) ProvidersForField(field string) []Provider {
 96Ôćĺ	var result []Provider
 97Ôćĺ	for _, p := range r.providers {
 98Ôćĺ		for _, f := range p.FieldsProvided {
 99Ôćĺ			if f == field {
100Ôćĺ				result = append(result, p)
101Ôćĺ				break
102Ôćĺ			}
103Ôćĺ		}
104Ôćĺ	}
105Ôćĺ	return result
106Ôćĺ}
107Ôćĺ
108Ôćĺ// Count returns the number of loaded providers.
109Ôćĺfunc (r *ProviderRegistry) Count() int {
110Ôćĺ	return len(r.providers)
111Ôćĺ}
