 23Ôćĺfunc checkExistingConnection(id string) (bool, string) {
 24Ôćĺ	if !project.IsNurgeProject(".") {
 25Ôćĺ		return false, ""
 26Ôćĺ	}
 27Ôćĺ	cfg, err := project.Load()
 28Ôćĺ	if err != nil {
 29Ôćĺ		return false, ""
 30Ôćĺ	}
 31Ôćĺ	cs, ok := cfg.Connectors[id]
 32Ôćĺ	if !ok || !cs.Connected {
 33Ôćĺ		return false, ""
 34Ôćĺ	}
 35Ôćĺ	return true, cs.Account
 36Ôćĺ}
