 56Ôćĺvar connectCmd = &cobra.Command{
 57Ôćĺ	Use:   "connect <service>",
 58Ôćĺ	Short: "Connect a service (gmail, linkedin)",
 59Ôćĺ	Args:  cobra.ExactArgs(1),
 60Ôćĺ	RunE: func(cmd *cobra.Command, args []string) error {
 61Ôćĺ		id := args[0]
 62Ôćĺ		if connected, account := checkExistingConnection(id); connected {
 63Ôćĺ			if !forceConnect {
 64Ôćĺ				fmt.Fprintf(os.Stderr, "  %s is already connected (%s)\n  Use --force to reconnect\n", id, account)
 65Ôćĺ				return fmt.Errorf("%s already connected, use --force to overwrite", id)
 66Ôćĺ			}
 67Ôćĺ			// Clean up old connection state before reconnecting
 68Ôćĺ			fmt.Fprintf(os.Stderr, "  Replacing existing %s connection (%s)...\n", id, account)
 69Ôćĺ			tokenDir := fmt.Sprintf(".nurge/connectors/%s", id)
 70Ôćĺ			_ = os.RemoveAll(tokenDir)
 71Ôćĺ		}
 72Ôćĺ		cleanup, err := acquireConnectLock(id)
 73Ôćĺ		if err != nil {
 74Ôćĺ			return err
 75Ôćĺ		}
 76Ôćĺ		defer cleanup()
 77Ôćĺ		switch id {
 78Ôćĺ		case "gmail":
 79Ôćĺ			return connectGmail()
 80Ôćĺ		case "linkedin":
 81Ôćĺ			return connectLinkedIn()
 82Ôćĺ		default:
 83Ôćĺ			registry, err := connector.LoadRegistry(projectLocalDefs)
 84Ôćĺ			if err != nil {
 85Ôćĺ				return fmt.Errorf("loading connector registry: %w", err)
 86Ôćĺ			}
 87Ôćĺ			var found *connector.ConnectorDef
 88Ôćĺ			for i := range registry {
 89Ôćĺ				if registry[i].ID == id {
 90Ôćĺ					found = &registry[i]
 91Ôćĺ					break
 92Ôćĺ				}
 93Ôćĺ			}
 94Ôćĺ			if found == nil {
 95Ôćĺ				return fmt.Errorf("unknown connector: %s\n  Run `nurge connectors available` to see all connectors", id)
 96Ôćĺ			}
 97Ôćĺ			c := connector.NewFromDef(*found, "")
 98Ôćĺ			result, err := c.Connect(cmd.Context())
 99Ôćĺ			if err != nil {
100Ôćĺ				return fmt.Errorf("connecting %s: %w", id, err)
101Ôćĺ			}
102Ôćĺ			if project.IsNurgeProject(".") {
103Ôćĺ				_ = project.SetConnector(id, found.Type, result.Account)
104Ôćĺ			}
105Ôćĺ			fmt.Fprintf(os.Stderr, "  \033[32mÔťô\033[0m %s connected (%s)\n", found.Name, result.Account)
106Ôćĺ		}
107Ôćĺ		return nil
108Ôćĺ	},
109Ôćĺ}
