111Ôćĺfunc connectGmail() error {
112Ôćĺ	af, err := account.LoadAuth()
113Ôćĺ	if err != nil || af.Token == "" {
114Ôćĺ		return fmt.Errorf("not logged in. Run: nurge account login")
115Ôćĺ	}
116Ôćĺ
117Ôćĺ	client := account.NewConvexClient(cmdutil.GetConvexURL())
118Ôćĺ
119Ôćĺ	fmt.Fprintf(os.Stderr, "  Requesting Gmail connection...\n")
120Ôćĺ	resp, err := client.ConnectGmail(af.Token)
121Ôćĺ	if err != nil {
122Ôćĺ		return fmt.Errorf("connect failed: %w", err)
123Ôćĺ	}
124Ôćĺ
125Ôćĺ	if resp.AlreadyConnected {
126Ôćĺ		if resp.MaxReached {
127Ôćĺ			fmt.Fprintf(os.Stderr, "  \033[32mÔťô\033[0m Max 2 Gmail accounts connected (%s)\n", resp.Email)
128Ôćĺ		} else {
129Ôćĺ			fmt.Fprintf(os.Stderr, "  \033[32mÔťô\033[0m Gmail already connected (%s)\n", resp.Email)
130Ôćĺ		}
131Ôćĺ		if project.IsNurgeProject(".") {
132Ôćĺ			_ = project.SetConnector("gmail", "email", resp.Email)
133Ôćĺ		}
134Ôćĺ		return nil
135Ôćĺ	}
136Ôćĺ
137Ôćĺ	fmt.Fprintf(os.Stderr, "  Opening browser to connect Gmail...\n")
138Ôćĺ	if err := util.OpenBrowser(resp.URL); err != nil {
139Ôćĺ		fmt.Fprintf(os.Stderr, "  Could not open browser. Please visit:\n  %s\n", resp.URL)
140Ôćĺ	}
141Ôćĺ
142Ôćĺ	fmt.Fprintf(os.Stderr, "  Waiting for Gmail connection...")
143Ôćĺ	timeout := time.After(5 * time.Minute)
144Ôćĺ	ticker := time.NewTicker(2 * time.Second)
145Ôćĺ	defer ticker.Stop()
146Ôćĺ
147Ôćĺ	for {
148Ôćĺ		select {
149Ôćĺ		case <-timeout:
150Ôćĺ			fmt.Fprintf(os.Stderr, "\n")
151Ôćĺ			return fmt.Errorf("timed out after 5 minutes waiting for Gmail connection.\n  Run `nurge connect gmail` to try again")
152Ôćĺ		case <-ticker.C:
153Ôćĺ			status, err := client.ConnectionStatus(af.Token, "GOOGLE")
154Ôćĺ			if err != nil {
155Ôćĺ				continue
156Ôćĺ			}
157Ôćĺ			if status.Connected {
158Ôćĺ				fmt.Fprintf(os.Stderr, "\n  \033[32mÔťô\033[0m Gmail connected (%s)\n", status.Email)
159Ôćĺ				if project.IsNurgeProject(".") {
160Ôćĺ					_ = project.SetConnector("gmail", "email", status.Email)
161Ôćĺ				}
162Ôćĺ				return nil
163Ôćĺ			}
164Ôćĺ			fmt.Fprintf(os.Stderr, ".")
165Ôćĺ		}
166Ôćĺ	}
167Ôćĺ}
