 11Ôćĺconst configFile = ".nurge/config.json"
 12Ôćĺconst configLockFile = ".nurge/config.lock"
 13Ôćĺ
 14Ôćĺ// withConfigLock acquires an exclusive file lock on the config lockfile,
 15Ôćĺ// runs fn, then releases the lock. This prevents TOCTOU race conditions
 16Ôćĺ// when multiple processes do Load -> modify -> Write concurrently.
 17Ôćĺfunc withConfigLock(fn func() error) error {
 18Ôćĺ	f, err := os.OpenFile(configLockFile, os.O_CREATE|os.O_RDWR, 0600)
 19Ôćĺ	if err != nil {
 20Ôćĺ		return fmt.Errorf("opening config lock: %w", err)
 21Ôćĺ	}
 22Ôćĺ	defer f.Close()
 23Ôćĺ
 24Ôćĺ	if err := flockExclusive(int(f.Fd())); err != nil {
 25Ôćĺ		return fmt.Errorf("acquiring config lock: %w", err)
 26Ôćĺ	}
 27Ôćĺ	defer flockUnlock(int(f.Fd()))
 28Ôćĺ
 29Ôćĺ	return fn()
 30Ôćĺ}
