package connector

import (
	"fmt"
	"net/url"

	"gopkg.in/yaml.v3"
)

// YAMLConnector is the parsed representation of a connector YAML file.
type YAMLConnector struct {
	SchemaVersion int          `yaml:"schema_version"`
	ID            string       `yaml:"id"`
	Name          string       `yaml:"name"`
	Type          string       `yaml:"type"`
	Tier          int          `yaml:"tier"`
	Required      bool         `yaml:"required"`
	Description   string       `yaml:"description"`
	Icon          string       `yaml:"icon"`
	Auth          AuthConfig   `yaml:"auth"`
	Credentials   CredConfig   `yaml:"credentials"`
	Verify        VerifyConfig `yaml:"verify"`
	Proxy         ProxyConfig  `yaml:"proxy"`
}

// AuthConfig describes how to authenticate with the service.
type AuthConfig struct {
	Method       string            `yaml:"method"` // oauth2, api_key, basic, webhook
	AuthorizeURL string            `yaml:"authorize_url"`
	TokenURL     string            `yaml:"token_url"`
	Scopes       []string          `yaml:"scopes"`
	AuthStyle    string            `yaml:"auth_style"`   // in_params, in_header
	ExtraParams  map[string]string `yaml:"extra_params"`
	// api_key fields
	Header     string `yaml:"header"`
	QueryParam string `yaml:"query_param"`
	EnvVar     string `yaml:"env_var"`
	// basic auth fields
	UsernameVar string `yaml:"username_var"`
	PasswordVar string `yaml:"password_var"`
	// webhook fields
	URLVar string `yaml:"url_var"`
}

// CredConfig describes where credentials come from.
type CredConfig struct {
	Source          string `yaml:"source"` // env, bundled, google_json, file, prompt
	ClientIDVar     string `yaml:"client_id_var"`
	ClientSecretVar string `yaml:"client_secret_var"`
}

// VerifyConfig describes the connection verification call.
type VerifyConfig struct {
	URL           string            `yaml:"url"`
	Method        string            `yaml:"method"`
	Headers       map[string]string `yaml:"headers"`
	AccountFields []string          `yaml:"account_fields"`
	AccountLabel  string            `yaml:"account_label"`
}

// ProxyConfig describes how to call the service's API.
type ProxyConfig struct {
	BaseURL    string `yaml:"base_url"`
	AuthHeader string `yaml:"auth_header"`
}

// ParseYAML parses and validates a connector YAML definition.
func ParseYAML(data []byte) (*YAMLConnector, error) {
	var def YAMLConnector
	if err := yaml.Unmarshal(data, &def); err != nil {
		return nil, fmt.Errorf("parsing YAML: %w", err)
	}
	if err := validateDef(&def); err != nil {
		return nil, err
	}
	// Defaults
	if def.Tier == 0 {
		def.Tier = 2
	}
	if def.Verify.Method == "" {
		def.Verify.Method = "GET"
	}
	return &def, nil
}

func validateDef(d *YAMLConnector) error {
	// Compatibility note: only schema_version 1 is currently supported.
	// Future versions may add new fields or change semantics. Definitions
	// with a different schema_version are rejected to prevent silent
	// misinterpretation of newer formats.
	if d.SchemaVersion != 1 {
		return fmt.Errorf("connector definition has unsupported schema_version: %d (expected 1)", d.SchemaVersion)
	}
	if d.ID == "" {
		return fmt.Errorf("connector definition missing required field: id")
	}
	if d.Name == "" {
		return fmt.Errorf("connector %q missing required field: name", d.ID)
	}
	if d.Type == "" {
		return fmt.Errorf("connector %q missing required field: type", d.ID)
	}
	if d.Auth.Method == "" {
		return fmt.Errorf("connector %q missing required field: auth.method", d.ID)
	}

	switch d.Auth.Method {
	case "oauth2":
		if d.Auth.AuthorizeURL == "" {
			return fmt.Errorf("connector %q (oauth2) missing auth.authorize_url", d.ID)
		}
		if d.Auth.TokenURL == "" {
			return fmt.Errorf("connector %q (oauth2) missing auth.token_url", d.ID)
		}

		// Validate that AuthorizeURL and TokenURL are valid URLs
		if _, err := url.ParseRequestURI(d.Auth.AuthorizeURL); err != nil {
			return fmt.Errorf("connector %q (oauth2) has invalid auth.authorize_url %q: %w", d.ID, d.Auth.AuthorizeURL, err)
		}
		if _, err := url.ParseRequestURI(d.Auth.TokenURL); err != nil {
			return fmt.Errorf("connector %q (oauth2) has invalid auth.token_url %q: %w", d.ID, d.Auth.TokenURL, err)
		}

		// Validate that scopes are non-empty for OAuth2
		if len(d.Auth.Scopes) == 0 {
			return fmt.Errorf("connector %q (oauth2) has empty auth.scopes (at least one scope is required)", d.ID)
		}

	case "api_key":
		if d.Auth.Header == "" && d.Auth.QueryParam == "" {
			return fmt.Errorf("connector %q (api_key) missing auth.header or auth.query_param", d.ID)
		}
	case "basic":
		// valid -- credentials resolved at connect time
	case "webhook":
		// valid -- URL resolved at connect time
	default:
		return fmt.Errorf("connector %q has unknown auth.method: %q", d.ID, d.Auth.Method)
	}

	return nil
}

package connector

import (
	"testing"
)

func TestParseYAML_Gmail(t *testing.T) {
	data := []byte(`
schema_version: 1
id: gmail
name: Gmail
type: email
tier: 1
required: true
auth:
  method: oauth2
  authorize_url: https://accounts.google.com/o/oauth2/auth
  token_url: https://oauth2.googleapis.com/token
  scopes:
    - https://www.googleapis.com/auth/gmail.readonly
credentials:
  source: google_json
verify:
  url: "https://gmail.googleapis.com/gmail/v1/users/me/profile"
  account_fields:
    - emailAddress
  account_label: Email
`)

	def, err := ParseYAML(data)
	if err != nil {
		t.Fatalf("ParseYAML: %v", err)
	}
	if def.ID != "gmail" {
		t.Errorf("ID = %q, want gmail", def.ID)
	}
	if def.Auth.Method != "oauth2" {
		t.Errorf("Auth.Method = %q, want oauth2", def.Auth.Method)
	}
	if def.Tier != 1 {
		t.Errorf("Tier = %d, want 1", def.Tier)
	}
	if !def.Required {
		t.Error("Required = false, want true")
	}
	if def.Credentials.Source != "google_json" {
		t.Errorf("Credentials.Source = %q, want google_json", def.Credentials.Source)
	}
	if len(def.Verify.AccountFields) != 1 || def.Verify.AccountFields[0] != "emailAddress" {
		t.Errorf("Verify.AccountFields = %v, want [emailAddress]", def.Verify.AccountFields)
	}
}

func TestParseYAML_APIKey(t *testing.T) {
	data := []byte(`
schema_version: 1
id: apollo
name: Apollo
type: enrichment
tier: 3
auth:
  method: api_key
  header: X-Api-Key
  env_var: APOLLO_API_KEY
verify:
  url: "https://api.apollo.io/v1/auth/health"
  account_fields:
    - email
  account_label: Account
`)

	def, err := ParseYAML(data)
	if err != nil {
		t.Fatalf("ParseYAML: %v", err)
	}
	if def.Auth.Method != "api_key" {
		t.Errorf("Auth.Method = %q, want api_key", def.Auth.Method)
	}
	if def.Auth.Header != "X-Api-Key" {
		t.Errorf("Auth.Header = %q, want X-Api-Key", def.Auth.Header)
	}
	if def.Auth.EnvVar != "APOLLO_API_KEY" {
		t.Errorf("Auth.EnvVar = %q, want APOLLO_API_KEY", def.Auth.EnvVar)
	}
}

func TestValidateYAML_MissingID(t *testing.T) {
	data := []byte(`
schema_version: 1
name: Test
type: crm
auth:
  method: oauth2
  authorize_url: https://example.com/auth
  token_url: https://example.com/token
`)

	_, err := ParseYAML(data)
	if err == nil {
		t.Fatal("expected error for missing id")
	}
}

func TestValidateYAML_OAuth2MissingURLs(t *testing.T) {
	data := []byte(`
schema_version: 1
id: test
name: Test
type: crm
auth:
  method: oauth2
`)

	_, err := ParseYAML(data)
	if err == nil {
		t.Fatal("expected error for oauth2 missing URLs")
	}
}

func TestValidateYAML_APIKeyMissingHeader(t *testing.T) {
	data := []byte(`
schema_version: 1
id: test
name: Test
type: enrichment
auth:
  method: api_key
`)

	_, err := ParseYAML(data)
	if err == nil {
		t.Fatal("expected error for api_key missing header")
	}
}

