package conn

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/cmd/cmdutil"
	"github.com/usenurge/nurgesh/internal/connector"
	"github.com/usenurge/nurgesh/internal/project"
)

const projectLocalDefs = ".nurge/connectors/definitions"

var connectorsCmd = &cobra.Command{
	Use:   "connectors",
	Short: "List connected services",
	RunE: func(cmd *cobra.Command, args []string) error {
		cfg, err := project.Load()
		if err != nil {
			return fmt.Errorf("loading config: %w", err)
		}

		registry, err := connector.LoadRegistry(projectLocalDefs)
		if err != nil {
			return fmt.Errorf("loading registry: %w", err)
		}

		hasAny := false
		for _, def := range registry {
			cs, ok := cfg.Connectors[def.ID]
			if !ok || !cs.Connected {
				continue
			}
			hasAny = true
			fmt.Printf("  \033[32mÔťô\033[0m %-10s %s\n", def.Name, cs.Account)
		}

		if !hasAny {
			fmt.Println("  No connectors configured. Run `nurge connect gmail` to connect.")
		}

		return nil
	},
}

// connectorsAvailableCmd lists ALL known connectors grouped by type, with connection status.
var connectorsAvailableCmd = &cobra.Command{
	Use:   "available",
	Short: "List all available connectors (bundled + project-local)",
	RunE: func(cmd *cobra.Command, args []string) error {
		// Config is optional ÔÇö if not in a project dir, just omit status.
		cfg, _ := project.Load()

		registry, err := connector.LoadRegistry(projectLocalDefs)
		if err != nil {
			return fmt.Errorf("loading registry: %w", err)
		}

		// Group by type.
		groups := map[string][]connector.ConnectorDef{}
		order := []string{}
		seen := map[string]bool{}
		for _, def := range registry {
			if !seen[def.Type] {
				seen[def.Type] = true
				order = append(order, def.Type)
			}
			groups[def.Type] = append(groups[def.Type], def)
		}

		for _, typ := range order {
			// Capitalise the type heading.
			heading := strings.ToUpper(typ[:1]) + typ[1:]
			fmt.Printf("  %s\n", heading)
			for _, def := range groups[typ] {
				requiredMark := ""
				if def.Required {
					requiredMark = " *"
				}
				statusSuffix := ""
				if cfg != nil {
					if cs, ok := cfg.Connectors[def.ID]; ok && cs.Connected {
						statusSuffix = fmt.Sprintf(" (connected: %s)", cs.Account)
					}
				}
				fmt.Printf("    %-15s %-20s%s%s\n", def.ID, def.Name, requiredMark, statusSuffix)
			}
		}

		return nil
	},
}

// connectorsValidateCmd validates a connector YAML file.
var connectorsValidateCmd = &cobra.Command{
	Use:   "validate <file>",
	Short: "Validate a connector YAML definition file",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		path := args[0]
		data, err := os.ReadFile(path)
		if err != nil {
			return fmt.Errorf("reading file %q: %w", path, err)
		}

		def, err := connector.ParseYAML(data)
		if err != nil {
			fmt.Printf("invalid: %s\n  %v\n", path, err)
			return err
		}

		fmt.Printf("valid: %s (id=%s, type=%s, auth=%s)\n", path, def.ID, def.Type, def.Auth.Method)
		return nil
	},
}

// connectorsInfoFormat is the --format flag for the info subcommand.
var connectorsInfoFormat string

// infoOutput is used for JSON marshalling of connector info.
type infoOutput struct {
	ID         string      `json:"id"`
	Name       string      `json:"name"`
	Type       string      `json:"type"`
	Tier       int         `json:"tier"`
	Required   bool        `json:"required"`
	AuthMethod string      `json:"auth_method"`
	Proxy      proxyOutput `json:"proxy"`
}

type proxyOutput struct {
	BaseURL    string `json:"base_url"`
	AuthHeader string `json:"auth_header"`
}

// connectorsInfoCmd looks up a connector by ID and prints its details.
var connectorsInfoCmd = &cobra.Command{
	Use:   "info <id>",
	Short: "Show details for a connector",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		id := args[0]

		registry, err := connector.LoadRegistry(projectLocalDefs)
		if err != nil {
			return fmt.Errorf("loading registry: %w", err)
		}

		var found *connector.ConnectorDef
		for i := range registry {
			if registry[i].ID == id {
				found = &registry[i]
				break
			}
		}
		if found == nil {
			return fmt.Errorf("connector %q not found", id)
		}

		out := infoOutput{
			ID:         found.ID,
			Name:       found.Name,
			Type:       found.Type,
			Tier:       found.Tier,
			Required:   found.Required,
			AuthMethod: found.Def.Auth.Method,
			Proxy: proxyOutput{
				BaseURL:    found.Def.Proxy.BaseURL,
				AuthHeader: found.Def.Proxy.AuthHeader,
			},
		}

		if connectorsInfoFormat == "json" {
			return cmdutil.OutputJSON(out)
		}

		// Plain text output.
		fmt.Printf("ID:          %s\n", out.ID)
		fmt.Printf("Name:        %s\n", out.Name)
		fmt.Printf("Type:        %s\n", out.Type)
		fmt.Printf("Tier:        %d\n", out.Tier)
		fmt.Printf("Required:    %v\n", out.Required)
		fmt.Printf("Auth method: %s\n", out.AuthMethod)
		if out.Proxy.BaseURL != "" {
			fmt.Printf("Proxy URL:   %s\n", out.Proxy.BaseURL)
		}
		return nil
	},
}

// connectorsAddFile is the --file flag for the add subcommand.
var connectorsAddFile string

// connectorsAddCmd validates a YAML file and installs it into the project-local definitions dir.
var connectorsAddCmd = &cobra.Command{
	Use:   "add",
	Short: "Add a project-local connector definition",
	RunE: func(cmd *cobra.Command, args []string) error {
		if connectorsAddFile == "" {
			return fmt.Errorf("--file is required")
		}

		data, err := os.ReadFile(connectorsAddFile)
		if err != nil {
			return fmt.Errorf("reading file %q: %w", connectorsAddFile, err)
		}

		def, err := connector.ParseYAML(data)
		if err != nil {
			return fmt.Errorf("invalid connector definition: %w", err)
		}

		destDir := projectLocalDefs
		if err := os.MkdirAll(destDir, 0755); err != nil {
			return fmt.Errorf("creating definitions directory: %w", err)
		}

		dest := filepath.Join(destDir, def.ID+".yaml")
		if err := os.WriteFile(dest, data, 0644); err != nil {
			return fmt.Errorf("writing definition: %w", err)
		}

		fmt.Printf("\033[32mÔťô\033[0m Connector %q added to %s\n", def.ID, dest)
		return nil
	},
}

func init() {
	// info --format flag
	connectorsInfoCmd.Flags().StringVar(&connectorsInfoFormat, "format", "", "Output format: json or plain (default)")

	// add --file flag
	connectorsAddCmd.Flags().StringVar(&connectorsAddFile, "file", "", "Path to connector YAML definition file")

	connectorsCmd.AddCommand(connectorsAvailableCmd)
	connectorsCmd.AddCommand(connectorsValidateCmd)
	connectorsCmd.AddCommand(connectorsInfoCmd)
	connectorsCmd.AddCommand(connectorsAddCmd)
	connectorsCmd.AddCommand(verifyCmd)

}

