package project

import (
	"encoding/json"
	"fmt"
	"log"
	"os"
	"path/filepath"
	"time"
)

type hooksStep struct{}

func (s *hooksStep) Name() string { return "Claude Code hooks installed" }

// hookEntry is a single hook within a matcher group.
// Exactly one of command or prompt must be set.
type hookEntry struct {
	command string // for type "command"
	prompt  string // for type "prompt"
}

// hookGroup defines a matcher group with its hooks for a given event.
type hookGroup struct {
	event   string
	matcher string
	hooks   []hookEntry
}

// requiredHookGroups defines all hook groups nurge needs installed.
// Hooks sharing the same event+matcher are grouped together (matching entire.io's pattern).
var requiredHookGroups = []hookGroup{
	{
		event:   "PostToolUse",
		matcher: "Bash",
		hooks:   []hookEntry{{command: "nurge hook post-tool-use"}},
	},
	{
		event:   "SessionStart",
		matcher: "",
		hooks:   []hookEntry{{command: "nurge hook session-start"}},
	},
	{
		event:   "UserPromptSubmit",
		matcher: "",
		hooks:   []hookEntry{{command: "nurge hook user-prompt"}},
	},
	{
		event:   "Stop",
		matcher: "",
		hooks: []hookEntry{
			{command: "nurge hook stop"},
			{prompt: "Before finishing, capture any new insights from this session. If you learned something about tone preferences, ICP refinements, product positioning, messaging patterns, competitor intel, or user preferences, save each as: nurge learn save --type <type> (types: tone, icp, product, pattern, preference, competitor). Only save non-obvious insights that will help future sessions. Skip if nothing new was learned. Keep each learning to 1-2 sentences."},
		},
	},
	{
		event:   "SessionEnd",
		matcher: "",
		hooks:   []hookEntry{{command: "nurge hook session-end"}},
	},
}

func (s *hooksStep) Done() (bool, error) {
	data, err := os.ReadFile(claudeSettingsPath())
	if err != nil {
		if os.IsNotExist(err) {
			return false, nil
		}
		return false, err
	}

	var settings map[string]any
	if err := json.Unmarshal(data, &settings); err != nil {
		return false, nil
	}

	hooks, ok := settings["hooks"].(map[string]any)
	if !ok {
		return false, nil
	}

	for _, g := range requiredHookGroups {
		for _, h := range g.hooks {
			if !hookEntryExists(hooks, g.event, h) {
				return false, nil
			}
		}
	}

	// Validate hook structure: each hook entry must have "type" and either "command" or "prompt"
	for _, g := range requiredHookGroups {
		arr, ok := hooks[g.event].([]any)
		if !ok {
			continue
		}
		for _, item := range arr {
			m, ok := item.(map[string]any)
			if !ok {
				continue
			}
			innerHooks, ok := m["hooks"].([]any)
			if !ok {
				continue
			}
			for _, h := range innerHooks {
				hm, ok := h.(map[string]any)
				if !ok {
					return false, nil
				}
				if _, hasType := hm["type"]; !hasType {
					return false, nil
				}
				_, hasCmd := hm["command"]
				_, hasPrompt := hm["prompt"]
				if !hasCmd && !hasPrompt {
					return false, nil
				}
			}
		}
	}

	return true, nil
}

func (s *hooksStep) Run() error {
	settingsPath := claudeSettingsPath()

	if err := os.MkdirAll(filepath.Dir(settingsPath), 0700); err != nil {
		return fmt.Errorf("creating .claude/: %w", err)
	}

	settings := make(map[string]any)
	if data, err := os.ReadFile(settingsPath); err == nil {
		if jsonErr := json.Unmarshal(data, &settings); jsonErr != nil {
			backupPath, backupErr := backupInvalidClaudeSettings(settingsPath, data)
			if backupErr != nil {
				return fmt.Errorf("invalid %s and failed to back it up: %w", settingsPath, backupErr)
			}
			return fmt.Errorf("invalid %s; backed it up to %s and left the original untouched", settingsPath, backupPath)
		}
	} else if !os.IsNotExist(err) {
		return fmt.Errorf("reading %s: %w", settingsPath, err)
	}

	hooks, ok := settings["hooks"].(map[string]any)
	if !ok || hooks == nil {
		hooks = make(map[string]any)
	}

	for _, g := range requiredHookGroups {
		// Collect entries that are missing
		var missing []hookEntry
		for _, h := range g.hooks {
			if !hookEntryExists(hooks, g.event, h) {
				missing = append(missing, h)
			}
		}
		if len(missing) == 0 {
			continue
		}

		// Find existing matcher entry for this event+matcher, or create one
		eventHooks, _ := hooks[g.event].([]any)
		matcherIdx := -1
		for i, item := range eventHooks {
			m, ok := item.(map[string]any)
			if !ok {
				continue
			}
			if matcher, _ := m["matcher"].(string); matcher == g.matcher {
				matcherIdx = i
				break
			}
		}

		if matcherIdx >= 0 {
			entry, ok := eventHooks[matcherIdx].(map[string]any)
			if !ok {
				continue
			}
			innerHooks, _ := entry["hooks"].([]any)
			for _, h := range missing {
				innerHooks = append(innerHooks, hookEntryToJSON(h))
			}
			entry["hooks"] = innerHooks
		} else {
			var innerHooks []any
			for _, h := range g.hooks {
				innerHooks = append(innerHooks, hookEntryToJSON(h))
			}
			entry := map[string]any{
				"matcher": g.matcher,
				"hooks":   innerHooks,
			}
			eventHooks = append(eventHooks, entry)
		}
		hooks[g.event] = eventHooks
	}

	settings["hooks"] = hooks

	// Sync permissions into the settings
	syncPermissionsInto(settings)

	data, err := json.MarshalIndent(settings, "", "  ")
	if err != nil {
		return fmt.Errorf("marshaling settings: %w", err)
	}

	if err := writeFileAtomic(settingsPath, data, 0600); err != nil {
		return fmt.Errorf("writing settings: %w", err)
	}

	return nil
}

// hookEntryExists checks if a specific hook entry (command or prompt) already
// exists under the given event key.
func hookEntryExists(hooks map[string]any, event string, entry hookEntry) bool {
	arr, ok := hooks[event].([]any)
	if !ok {
		return false
	}
	for _, item := range arr {
		m, ok := item.(map[string]any)
		if !ok {
			continue
		}
		innerHooks, ok := m["hooks"].([]any)
		if !ok {
			continue
		}
		for _, h := range innerHooks {
			hm, ok := h.(map[string]any)
			if !ok {
				continue
			}
			if entry.command != "" {
				if cmd, ok := hm["command"].(string); ok && cmd == entry.command {
					return true
				}
			}
			if entry.prompt != "" {
				if p, ok := hm["prompt"].(string); ok && p == entry.prompt {
					return true
				}
			}
		}
	}
	return false
}

// hookCommandExists is a convenience wrapper for checking command hooks.
func hookCommandExists(hooks map[string]any, event, command string) bool {
	return hookEntryExists(hooks, event, hookEntry{command: command})
}

func containsString(arr []any, s string) bool {
	for _, v := range arr {
		if str, ok := v.(string); ok && str == s {
			return true
		}
	}
	return false
}

func hookEntryToJSON(entry hookEntry) map[string]any {
	if entry.prompt != "" {
		return map[string]any{"type": "prompt", "prompt": entry.prompt}
	}
	return map[string]any{"type": "command", "command": entry.command}
}

func claudeSettingsPath() string {
	return filepath.Join(".claude", "settings.json")
}

// RequiredPermissions lists all allow-rules nurge needs in .claude/settings.json.
// Kept in one place so init and session-start sync stay consistent.
var RequiredPermissions = []string{
	"Bash(nurge *)",
	"Bash(git *)",
	"Bash(go *)",
	"Bash(curl *)",
	"Bash(dig *)",
	"Bash(gh *)",
	"Bash(which *)",
	"Bash(ls *)",
	"Bash(mkdir *)",
	"Bash(cp *)",
	"Bash(mv *)",
	"Read",
	"Edit",
	"Write",
	"WebFetch",
	"WebSearch",
}

// syncPermissionsInto ensures all RequiredPermissions are present in the
// given settings map (mutates in place).
func syncPermissionsInto(settings map[string]any) {
	permissions, ok := settings["permissions"].(map[string]any)
	if !ok || permissions == nil {
		permissions = make(map[string]any)
	}
	allow, _ := permissions["allow"].([]any)
	for _, perm := range RequiredPermissions {
		if !containsString(allow, perm) {
			allow = append(allow, perm)
		}
	}
	permissions["allow"] = allow
	settings["permissions"] = permissions
}

// SyncPermissions reads .claude/settings.json, adds any missing required
// permissions, and writes the file back. Safe to call on every session start.
// Returns (added, error) where added is the number of new permissions inserted.
func SyncPermissions() (int, error) {
	settingsPath := claudeSettingsPath()

	settings := make(map[string]any)
	if data, err := os.ReadFile(settingsPath); err == nil {
		if jsonErr := json.Unmarshal(data, &settings); jsonErr != nil {
			backupPath, backupErr := backupInvalidClaudeSettings(settingsPath, data)
			if backupErr != nil {
				log.Printf("warning: invalid %s and backup failed during permission sync: %v", settingsPath, backupErr)
				return 0, fmt.Errorf("invalid %s and backup failed: %w", settingsPath, backupErr)
			}
			log.Printf("warning: invalid %s; backed it up to %s and skipped permission sync", settingsPath, backupPath)
			return 0, fmt.Errorf("invalid %s; backed it up to %s and skipped permission sync", settingsPath, backupPath)
		}
	} else if os.IsNotExist(err) {
		return 0, nil
	} else {
		return 0, err
	}

	before := countAllowPermissions(settings)
	syncPermissionsInto(settings)
	added := countAllowPermissions(settings) - before
	if added == 0 {
		return 0, nil
	}

	data, err := json.MarshalIndent(settings, "", "  ")
	if err != nil {
		return 0, fmt.Errorf("marshaling settings: %w", err)
	}
	if err := writeFileAtomic(settingsPath, data, 0600); err != nil {
		return 0, fmt.Errorf("writing settings: %w", err)
	}
	return added, nil
}

func countAllowPermissions(settings map[string]any) int {
	permissions, _ := settings["permissions"].(map[string]any)
	if permissions == nil {
		return 0
	}
	allow, _ := permissions["allow"].([]any)
	return len(allow)
}

func backupInvalidClaudeSettings(path string, data []byte) (string, error) {
	backupPath := fmt.Sprintf("%s.invalid-%d", path, time.Now().UTC().UnixNano())
	if err := writeFileAtomic(backupPath, data, 0600); err != nil {
		return "", err
	}
	return backupPath, nil
}

func writeFileAtomic(path string, data []byte, perm os.FileMode) error {
	tmpPath := path + ".tmp"
	if err := os.WriteFile(tmpPath, data, perm); err != nil {
		return err
	}
	if err := os.Rename(tmpPath, path); err != nil {
		os.Remove(tmpPath)
		return err
	}
	return nil
}

