    36Ôćĺ	// Capture session + sync event in a single DB open (graceful ÔÇö don't fail the hook)
    37Ôćĺ	if input != nil && input.SessionID != "" && db.Exists() {
    38Ôćĺ		if d, err := db.Open(); err == nil {
