    40Ôćĺ				session.Logger().Warn("session-create-failed", "session_id", input.SessionID, "error", createErr.Error())
    41Ôćĺ			}
    42Ôćĺ			if eventErr := session.AddEvent(d, input.SessionID, "session_start", input); eventErr != nil {
    43Ôćĺ				session.Logger().Warn("session-event-failed", "session_id", input.SessionID, "error", eventErr.Error())
    44Ôćĺ			}
    45Ôćĺ			if syncReport != nil && syncReport.Attempted {
    46Ôćĺ				if eventErr := session.AddEvent(d, input.SessionID, "sync_pull", syncReport); eventErr != nil {
    47Ôćĺ					session.Logger().Warn("sync-event-failed", "session_id", input.SessionID, "error", eventErr.Error())
    48Ôćĺ				}
    49Ôćĺ			}
    50Ôćĺ			d.Close()
    51Ôćĺ		} else {
    52Ôćĺ			session.Logger().Warn("db-open-failed", "error", err.Error())
    53Ôćĺ		}
    54Ôćĺ		session.Logger().Info("session-start", "session_id", input.SessionID, "model", input.Model)
    55Ôćĺ		session.FlushLog()
    56Ôćĺ	}
    57Ôćĺ
    58Ôćĺ	banner := buildBanner(s)
