}

// StoreGmailCredentials pushes an encrypted Gmail refresh token to Convex
// for server-side reply detection.
func (c *ConvexClient) StoreGmailCredentials(authToken, email, encryptedToken, tokenIv string) ([]byte, error) {
	return c.enrichPost(authToken, "/api/store-gmail-credentials", map[string]string{
		"email":                 email,
		"encryptedRefreshToken": encryptedToken,
		"tokenIv":               tokenIv,
		"scopes":                "gmail.readonly,gmail.send",
	})
}

func (c *ConvexClient) enrichPost(token, path string, payload interface{}) ([]byte, error) {
	body, err := json.Marshal(payload)
	if err != nil {
		return nil, fmt.Errorf("marshaling request: %w", err)
	}

	var resp *http.Response
	var lastErr error
	for attempt := 0; attempt < 3; attempt++ {
		if attempt > 0 {
			time.Sleep(time.Duration(1<<attempt) * time.Second)
		}
		enrichLimiter.wait()

		httpReq, err := http.NewRequest("POST", c.baseURL+path, bytes.NewReader(body))
		if err != nil {
			return nil, fmt.Errorf("creating request: %w", err)
		}
		httpReq.Header.Set("Content-Type", "application/json")
		httpReq.Header.Set("Authorization", "Bearer "+token)

		resp, lastErr = c.enrichClient.Do(httpReq)
		if lastErr == nil && resp.StatusCode < 500 {
			break
		}
		if resp != nil {
			resp.Body.Close()
		}
	}
	if lastErr != nil {
		return nil, fmt.Errorf("calling %s: %w", path, lastErr)
	}
	defer resp.Body.Close()

	data, err := io.ReadAll(io.LimitReader(resp.Body, 50*1024*1024))
	if err != nil {
		return nil, fmt.Errorf("reading response: %w", err)
	}

	if resp.StatusCode != 200 {
		var errResp struct {
			Error string `json:"error"`
		}
		json.Unmarshal(data, &errResp)
		if errResp.Error != "" {
			return nil, fmt.Errorf("%s", errResp.Error)
		}
		return nil, fmt.Errorf("HTTP %d: %s", resp.StatusCode, string(data))
	}

	return data, nil
}

