package cmdutil

import (
	"encoding/json"
	"os"
	"strings"
	"time"
)

var (
	BuildVersion  = "dev"
	BuildCommit   = "none"
	BuildDate     = "unknown"
	ConvexSiteURL = ""
)

// GetConvexURL returns the Convex site URL, allowing env var override for development.
func GetConvexURL() string {
	if env := os.Getenv("NURGE_CONVEX_URL"); env != "" {
		return env
	}
	return ConvexSiteURL
}

// GetDashboardURL returns the dashboard URL, allowing env var override for development.
func GetDashboardURL() string {
	if env := os.Getenv("NURGE_DASHBOARD_URL"); env != "" {
		return env
	}
	return "https://app.nurge.sh"
}

// Preview truncates a string to limit characters, collapsing newlines.
func Preview(body string, limit int) string {
	body = strings.TrimSpace(body)
	body = strings.ReplaceAll(body, "\n", " ")
	if limit <= 0 || len(body) <= limit {
		return body
	}
	return body[:limit-1] + "..."
}

// ShortDate formats an RFC3339 or datetime string to a short local format.
func ShortDate(value string) string {
	if value == "" {
		return value
	}
	if ts, err := time.Parse(time.RFC3339, value); err == nil {
		return ts.In(time.Local).Format("2006-01-02 15:04")
	}
	if len(value) >= 16 {
		return value[:16]
	}
	if len(value) >= 10 {
		return value[:10]
	}
	return value
}

// RecipientsJSON converts a comma-separated email string to a JSON array.
func RecipientsJSON(raw string) string {
	raw = strings.TrimSpace(raw)
	if raw == "" {
		return "[]"
	}
	parts := strings.Split(raw, ",")
	recipients := make([]string, 0, len(parts))
	for _, part := range parts {
		part = strings.TrimSpace(part)
		if part != "" {
			recipients = append(recipients, part)
		}
	}
	data, _ := json.Marshal(recipients)
	return string(data)
}

