package conn

import (
	"fmt"
	"os"
	"path/filepath"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/cmd/cmdutil"
	"github.com/usenurge/nurgesh/internal/account"
	"github.com/usenurge/nurgesh/internal/connector"
	"github.com/usenurge/nurgesh/internal/project"
)

// ÔöÇÔöÇ nurge connectors status <service> ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

var connectorsStatusFormat string

var connectorsStatusCmd = &cobra.Command{
	Use:   "status <service>",
	Short: "Check community status of a connector",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		serviceID := args[0]

		af, err := account.LoadAuth()
		if err != nil {
			return fmt.Errorf("not logged in: run `nurge account login` first")
		}

		client := account.NewConvexClient(cmdutil.GetConvexURL())
		status, err := client.ConnectorStatus(af.Token, serviceID)
		if err != nil {
			// Graceful degradation: if Convex is unreachable, report unknown
			if connectorsStatusFormat == "json" {
				return cmdutil.OutputJSON(map[string]any{
					"serviceId":       serviceID,
					"status":          "unknown",
					"submissionCount": 0,
					"requestCount":    0,
					"error":           err.Error(),
				})
			}
			fmt.Printf("  Could not reach Nurge server: %v\n", err)
			return nil
		}

		if connectorsStatusFormat == "json" {
			return cmdutil.OutputJSON(status)
		}

		// Plain text
		fmt.Printf("  Service:      %s\n", serviceID)
		fmt.Printf("  Status:       %s\n", status.Status)
		if status.NurgeOAuthRegistered {
			fmt.Printf("  OAuth app:    registered\n")
		}
		if status.KnownAuth != "" {
			fmt.Printf("  Auth method:  %s\n", status.KnownAuth)
		}
		if status.SubmissionCount > 0 {
			fmt.Printf("  Submissions:  %d\n", status.SubmissionCount)
		}
		if status.RequestCount > 0 {
			fmt.Printf("  Requests:     %d\n", status.RequestCount)
		}
		if status.LastVerifiedAt != "" {
			fmt.Printf("  Last verified: %s\n", cmdutil.ShortDate(status.LastVerifiedAt))
		}
		return nil
	},
}

// ÔöÇÔöÇ nurge connectors share <id> ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

var connectorsShareCmd = &cobra.Command{
	Use:   "share <id>",
	Short: "Share a working connector with the Nurge community",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		id := args[0]

		// 1. Check the connector is project-local (not bundled)
		yamlPath := filepath.Join(projectLocalDefs, id+".yaml")
		data, err := os.ReadFile(yamlPath)
		if err != nil {
			if os.IsNotExist(err) {
				return fmt.Errorf("no project-local connector %q found at %s", id, yamlPath)
			}
			return fmt.Errorf("reading connector: %w", err)
		}

		// 2. Reject bundled connector IDs
		bundled, err := connector.LoadBundledIDs()
		if err == nil {
			for _, bid := range bundled {
				if bid == id {
					return fmt.Errorf("cannot share bundled connector %q. If you've found improvements, please report them", id)
				}
			}
		}

		// 3. Parse and validate
		def, err := connector.ParseYAML(data)
		if err != nil {
			return fmt.Errorf("invalid connector YAML: %w", err)
		}

		// 4. Secret scan
		warnings := connector.ScanSecrets(def, data)
		if len(warnings) > 0 {
			fmt.Println("  Cannot share: secrets detected in connector YAML:")
			for _, w := range warnings {
				fmt.Printf("    - %s\n", w)
			}
			fmt.Println("  Remove actual credential values and use env var references instead.")
			return fmt.Errorf("secrets detected in connector YAML")
		}

		// 5. Check connector is actually connected
		cfg, err := project.Load()
		if err != nil {
			return fmt.Errorf("loading config: %w", err)
		}
		cs, ok := cfg.Connectors[id]
		if !ok || !cs.Connected {
			return fmt.Errorf("connector %q is not connected. Connect it first with `nurge connect %s`", id, id)
		}

		// 6. Load auth and upload
		af, err := account.LoadAuth()
		if err != nil {
			return fmt.Errorf("not logged in: run `nurge account login` first")
		}

		// Read API reference if present alongside YAML
		apiRef := ""
		apiRefPath := filepath.Join(projectLocalDefs, id+"-api.md")
		if refData, err := os.ReadFile(apiRefPath); err == nil {
			apiRef = string(refData)
		}

		client := account.NewConvexClient(cmdutil.GetConvexURL())
		result, err := client.ConnectorShare(af.Token, account.ConnectorShareRequest{
			ServiceID:     def.ID,
			YAMLContent:   string(data),
			APIReference:  apiRef,
			AuthMethod:    def.Auth.Method,
			ConnectorName: def.Name,
			ConnectorType: def.Type,
		})
		if err != nil {
			return fmt.Errorf("sharing connector: %w", err)
		}

		fmt.Printf("\033[32mÔťô\033[0m Shared! Submission #%d for %s. We'll review and add it to Nurge.\n", result.SubmissionCount, def.Name)
		return nil
	},
}

// ÔöÇÔöÇ nurge connectors request <id> ÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇÔöÇ

var (
	requestReason  string
	requestDocsURL string
)

var connectorsRequestCmd = &cobra.Command{
	Use:   "request <service>",
	Short: "Request a connector that can't be auto-built",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		serviceID := args[0]

		if requestReason == "" {
			return fmt.Errorf("--reason is required")
		}

		af, err := account.LoadAuth()
		if err != nil {
			return fmt.Errorf("not logged in: run `nurge account login` first")
		}

		client := account.NewConvexClient(cmdutil.GetConvexURL())
		result, err := client.ConnectorRequest(af.Token, account.ConnectorRequestReq{
			ServiceID: serviceID,
			Reason:    requestReason,
			DocsURL:   requestDocsURL,
		})
		if err != nil {
			return fmt.Errorf("requesting connector: %w", err)
		}

		if result.IsNew {
			fmt.Printf("\033[32mÔťô\033[0m Requested! You're the first to ask for %s. The team has been notified.\n", serviceID)
		} else {
			fmt.Printf("\033[32mÔťô\033[0m Your vote for %s has been added. %d users have requested this.\n", serviceID, result.VoteCount)
		}
		return nil
	},
}

func init() {
	connectorsStatusCmd.Flags().StringVar(&connectorsStatusFormat, "format", "", "Output format: json or plain (default)")
	connectorsRequestCmd.Flags().StringVar(&requestReason, "reason", "", "Why this connector can't be auto-built")
	connectorsRequestCmd.Flags().StringVar(&requestDocsURL, "docs-url", "", "URL to the service's API documentation")

	connectorsCmd.AddCommand(connectorsStatusCmd)
	connectorsCmd.AddCommand(connectorsShareCmd)
	connectorsCmd.AddCommand(connectorsRequestCmd)
}

