package connector

import (
	"fmt"
	"math"
	"regexp"
	"strings"

	"gopkg.in/yaml.v3"
)

// envVarPattern matches ALL_CAPS_WITH_UNDERSCORES names used for env vars.
var envVarPattern = regexp.MustCompile(`^[A-Z][A-Z0-9_]+$`)

// templateVarPattern matches template placeholders like {{access_token}} or {{api_key}}.
var templateVarPattern = regexp.MustCompile(`\{\{[a-z_]+\}\}`)

// credentialPatterns are regexes that match known credential formats.
var credentialPatterns = []struct {
	pattern *regexp.Regexp
	label   string
}{
	{regexp.MustCompile(`sk_live_\S+`), "Stripe live key"},
	{regexp.MustCompile(`sk_test_\S+`), "Stripe test key"},
	{regexp.MustCompile(`xoxb-\S+`), "Slack bot token"},
	{regexp.MustCompile(`xoxp-\S+`), "Slack user token"},
	{regexp.MustCompile(`ghp_\S+`), "GitHub personal access token"},
	{regexp.MustCompile(`gho_\S+`), "GitHub OAuth token"},
	{regexp.MustCompile(`ghs_\S+`), "GitHub server token"},
	{regexp.MustCompile(`AKIA[0-9A-Z]{16}`), "AWS access key"},
	{regexp.MustCompile(`ya29\.\S+`), "Google OAuth access token"},
	{regexp.MustCompile(`^Bearer \S+`), "hardcoded Bearer token"},
}

// base64BlobPattern matches long base64-encoded strings (>40 chars).
var base64BlobPattern = regexp.MustCompile(`^[A-Za-z0-9+/]{40,}={0,3}$`)

// ScanSecrets checks a YAMLConnector for embedded secrets that shouldn't be shared.
// Returns a list of warnings. If the list is non-empty, the connector should not be shared.
func ScanSecrets(def *YAMLConnector, rawYAML []byte) []string {
	var warnings []string

	// 1. Scan all string values in the raw YAML for high-entropy strings and credential patterns.
	warnings = append(warnings, scanYAMLValues(rawYAML)...)

	// 2. Check credential field values (client_id_var, client_secret_var).
	warnings = append(warnings, scanCredentialFields(def)...)

	// 3. Check proxy auth header for hardcoded tokens.
	warnings = append(warnings, scanAuthHeader(def)...)

	return warnings
}

// scanYAMLValues unmarshals the YAML into a generic structure and walks all
// string values, checking for high entropy and known credential patterns.
func scanYAMLValues(rawYAML []byte) []string {
	var raw map[string]interface{}
	if err := yaml.Unmarshal(rawYAML, &raw); err != nil {
		return nil
	}

	var warnings []string
	walkMap(raw, "", func(path, value string) {
		// Skip values that contain template variables -- these are placeholders, not secrets.
		if templateVarPattern.MatchString(value) {
			return
		}

		// Skip URLs -- structured strings, not secrets.
		if strings.HasPrefix(value, "http://") || strings.HasPrefix(value, "https://") {
			return
		}

		// Check known credential patterns.
		for _, cp := range credentialPatterns {
			if cp.pattern.MatchString(value) {
				warnings = append(warnings, fmt.Sprintf("known credential pattern (%s) in field %q", cp.label, path))
				return // one warning per value is enough
			}
		}

		// Check base64 blobs.
		if base64BlobPattern.MatchString(value) {
			warnings = append(warnings, fmt.Sprintf("possible base64-encoded secret in field %q (length %d)", path, len(value)))
			return
		}

		// Check high-entropy strings.
		if len(value) > 20 && shannonEntropy(value) > 4.0 {
			warnings = append(warnings, fmt.Sprintf("high-entropy string in field %q (entropy %.2f, length %d)", path, shannonEntropy(value), len(value)))
		}
	})

	return warnings
}

// walkMap recursively walks a YAML map and calls fn for every string value found.
func walkMap(m map[string]interface{}, prefix string, fn func(path, value string)) {
	for key, val := range m {
		path := key
		if prefix != "" {
			path = prefix + "." + key
		}
		walkValue(val, path, fn)
	}
}

// walkValue dispatches on the concrete type of a YAML value.
func walkValue(val interface{}, path string, fn func(path, value string)) {
	switch v := val.(type) {
	case string:
		fn(path, v)
	case map[string]interface{}:
		walkMap(v, path, fn)
	case []interface{}:
		for i, item := range v {
			walkValue(item, fmt.Sprintf("%s[%d]", path, i), fn)
		}
	}
}

// scanCredentialFields checks whether client_id_var and client_secret_var look
// like actual secret values rather than environment variable names.
func scanCredentialFields(def *YAMLConnector) []string {
	var warnings []string

	if v := def.Credentials.ClientIDVar; v != "" && !envVarPattern.MatchString(v) {
		warnings = append(warnings, fmt.Sprintf("credentials.client_id_var %q looks like an actual value, not an env var name (expected ALL_CAPS_WITH_UNDERSCORES)", v))
	}
	if v := def.Credentials.ClientSecretVar; v != "" && !envVarPattern.MatchString(v) {
		warnings = append(warnings, fmt.Sprintf("credentials.client_secret_var %q looks like an actual value, not an env var name (expected ALL_CAPS_WITH_UNDERSCORES)", v))
	}

	return warnings
}

// scanAuthHeader checks proxy.auth_header for hardcoded tokens. A valid auth
// header should use template variables like {{access_token}} or {{api_key}}.
func scanAuthHeader(def *YAMLConnector) []string {
	header := def.Proxy.AuthHeader
	if header == "" {
		return nil
	}

	// If the header contains a template variable, it's fine.
	if templateVarPattern.MatchString(header) {
		return nil
	}

	// No template variable found -- this looks like a hardcoded token.
	return []string{fmt.Sprintf("proxy.auth_header %q appears to contain a hardcoded token (expected template variable like {{access_token}})", header)}
}

// shannonEntropy calculates the Shannon entropy of a string in bits per character.
func shannonEntropy(s string) float64 {
	if len(s) == 0 {
		return 0
	}

	freq := make(map[rune]int)
	for _, c := range s {
		freq[c]++
	}

	length := float64(len([]rune(s)))
	entropy := 0.0
	for _, count := range freq {
		p := float64(count) / length
		if p > 0 {
			entropy -= p * math.Log2(p)
		}
	}

	return entropy
}

