	Use:   "remove <id>",
	Short: "Remove a project-local connector definition and its data",
	Args:  cobra.ExactArgs(1),
	RunE: func(cmd *cobra.Command, args []string) error {
		id := args[0]

		// 1. Refuse to remove bundled connectors.
		if connector.IsBundled(id) {
			return fmt.Errorf("cannot remove bundled connector %q. Only project-local connectors can be removed", id)
		}

		// 2. Check that a project-local YAML definition exists.
		yamlPath := filepath.Join(projectLocalDefs, id+".yaml")
		if _, err := os.Stat(yamlPath); os.IsNotExist(err) {
			return fmt.Errorf("no project-local connector %q found", id)
		}

		// 3. Remove the YAML definition file.
		if err := os.Remove(yamlPath); err != nil {
			return fmt.Errorf("removing definition %s: %w", yamlPath, err)
		}

		// 4. Remove the auth/token directory if it exists.
		authDir := fmt.Sprintf(".nurge/connectors/%s", id)
		if err := os.RemoveAll(authDir); err != nil {
			fmt.Fprintf(os.Stderr, "  warning: could not remove %s: %v\n", authDir, err)
		}

		// 5. Remove from config if present.
		if err := project.RemoveConnector(id); err != nil {
			fmt.Fprintf(os.Stderr, "  warning: could not update config: %v\n", err)
		}

		fmt.Printf("\033[32mÔťô\033[0m Connector %q removed\n", id)
		return nil
	},
}

