package skill

import (
	"fmt"
	"os"
	"path/filepath"
	"strings"

	"github.com/spf13/cobra"
	"github.com/usenurge/nurgesh/internal/assembly"
	"github.com/usenurge/nurgesh/internal/db"
	"github.com/usenurge/nurgesh/internal/session"
)

var installWrappersForce bool

var skillsInstallWrappersCmd = &cobra.Command{
	Use:   "install-wrappers",
	Short: "Install all 17 thin skill wrappers that invoke nurge context assemble",
	Long: `Installs thin SKILL.md wrappers for all 16 skills. Each wrapper invokes
nurge context assemble with the appropriate task type, then follows the
assembled instructions. The intelligence lives in knowledge atoms and the
assembly engine, not in the skill files themselves.

Use --force to overwrite existing skill files.`,
	RunE: func(cmd *cobra.Command, args []string) error {
		templates := assembly.ThinSkillTemplates()

		var installed, skipped []string

		for name, content := range templates {
			dir := filepath.Join(".claude", "skills", name)
			path := filepath.Join(dir, "SKILL.md")

			// Check if skill already exists on disk.
			if !installWrappersForce {
				if _, err := os.Stat(path); err == nil {
					skipped = append(skipped, name)
					continue
				}
			}

			if err := os.MkdirAll(dir, 0755); err != nil {
				return fmt.Errorf("creating directory %s: %w", dir, err)
			}
			if err := os.WriteFile(path, []byte(content), 0644); err != nil {
				return fmt.Errorf("writing %s: %w", path, err)
			}
			installed = append(installed, name)
		}

		// Save versions to DB if available.
		d, dbErr := db.Open()
		if dbErr == nil {
			defer d.Close()
			counts, err := session.CurrentSnapshotCounts(d)
			if err == nil {
				for name, content := range templates {
					// Only save versions for skills we actually wrote.
					for _, inst := range installed {
						if inst == name {
							_, _ = session.SaveSkillVersion(d, name, content, counts.EmailCount, counts.LearningCount)
							break
						}
					}
				}
			}
		}

		if len(installed) > 0 {
			fmt.Printf("Installed %d thin skill wrappers: %s\n", len(installed), strings.Join(installed, ", "))
		}
		if len(skipped) > 0 {
			fmt.Printf("Skipped %d existing skills (use --force to overwrite): %s\n", len(skipped), strings.Join(skipped, ", "))
		}
		if len(installed) == 0 && len(skipped) == 0 {
			fmt.Println("No skill templates available.")
		}

		return nil
	},
}

func init() {
	skillsInstallWrappersCmd.Flags().BoolVar(&installWrappersForce, "force", false, "Overwrite existing skill files")
	skillsCmd.AddCommand(skillsInstallWrappersCmd)
}

