func (s *skillStep) Done() (bool, error) {
	// Always overwrite to install latest version
	return false, nil
}

func (s *skillStep) Run() error {
	home, err := os.UserHomeDir()
	if err != nil {
		return fmt.Errorf("getting home dir: %w", err)
	}

	skillDir := filepath.Join(home, ".claude", "skills", "nurge-setup")
	if err := os.MkdirAll(skillDir, 0755); err != nil {
		return fmt.Errorf("creating skill dir: %w", err)
	}

	return fs.WalkDir(setupSkillFiles, "skills/setup", func(path string, d fs.DirEntry, err error) error {
		if err != nil {
			return err
		}
		if d.IsDir() {
			return nil
		}

		content, err := setupSkillFiles.ReadFile(path)
		if err != nil {
			return fmt.Errorf("reading embedded %s: %w", path, err)
		}

		destPath := filepath.Join(skillDir, d.Name())
		if err := os.WriteFile(destPath, content, 0644); err != nil {
			return fmt.Errorf("writing %s: %w", destPath, err)
		}

		return nil
	})
}

