package hook

import (
	"encoding/json"
	"os"
	"path/filepath"

	"github.com/usenurge/nurgesh/cmd/cmdutil"
	"github.com/usenurge/nurgesh/internal/account"
	"github.com/usenurge/nurgesh/internal/session"
)

// injectContext7Key fetches the context7 API key from Convex and writes it
// into the MCP server config so context7 is available this session.
// Graceful: logs warnings but never fails the session-start hook.
func injectContext7Key() {
	af, err := account.LoadAuth()
	if err != nil || af.Token == "" {
		return // not logged in, skip silently
	}

	client := account.NewConvexClient(cmdutil.GetConvexURL())
	resp, err := client.ConnectorContext7Key(af.Token)
	if err != nil {
		session.Logger().Warn("context7-key-fetch-failed", "error", err.Error())
		return
	}
	if resp.Key == "" {
		return // no key configured server-side
	}

	// Write the key as an environment variable in .claude/settings.local.json
	// (gitignored, session-scoped).
	settingsPath := filepath.Join(".claude", "settings.local.json")

	settings := make(map[string]any)
	if data, err := os.ReadFile(settingsPath); err == nil {
		json.Unmarshal(data, &settings)
	}

	// Ensure env section exists
	env, ok := settings["env"].(map[string]any)
	if !ok || env == nil {
		env = make(map[string]any)
	}

	// Only write if not already set (don't overwrite user's own key)
	if existing, ok := env["CONTEXT7_API_KEY"].(string); ok && existing != "" {
		return
	}

	env["CONTEXT7_API_KEY"] = resp.Key
	settings["env"] = env

	data, err := json.MarshalIndent(settings, "", "  ")
	if err != nil {
		session.Logger().Warn("context7-settings-marshal-failed", "error", err.Error())
		return
	}

	if err := os.MkdirAll(filepath.Dir(settingsPath), 0700); err != nil {
		session.Logger().Warn("context7-settings-dir-failed", "error", err.Error())
		return
	}

	// Write atomically
	tmpPath := settingsPath + ".tmp"
	if err := os.WriteFile(tmpPath, data, 0600); err != nil {
		session.Logger().Warn("context7-settings-write-failed", "error", err.Error())
		return
	}
	if err := os.Rename(tmpPath, settingsPath); err != nil {
		os.Remove(tmpPath)
		session.Logger().Warn("context7-settings-rename-failed", "error", err.Error())
	}
}

